        chatSessionRef.current = chat;

        setIsTyping(true);
        const response = await chat.sendMessage({ message: "Start the interview. Ask about the first item with its definition." });
        processResponse(response);

      } catch (error) {
        console.error("Failed to init chat", error);
        setMessages([{
             id: 'init-error',
             sender: 'ai',
             text: lang === 'ar' ? "فشل تهيئة المستشار المالي." : "Failed to initialize Financial Consultant.",
             isError: true
        }]);
        setIsTyping(false);
      }
    };

    initChat();
  }, [salary, lang, t.currency, retryTrigger]);

  const cleanAndParseJSON = (rawText: string) => {
    // Improved JSON Extraction:
    // 1. Remove markdown code blocks
    let jsonStr = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();

    // 2. Extract strictly from the first '{' to the last '}' to handle potential trailing artifacts (e.g. `}_`)
    const firstBrace = jsonStr.indexOf('{');
    const lastBrace = jsonStr.lastIndexOf('}');

    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
        jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
    }

    return JSON.parse(jsonStr);
  };

