    if (data.isFinal) {
        setQuickReplies([]);
        setIsFinished(true);

        if (data.rule) onUpdateRule(data.rule);
        if (data.expenses && Array.isArray(data.expenses)) {
             data.expenses.forEach((exp: any) => {
              let type: ExpenseType = ExpenseType.NEED;

              // Map AI response type to Enum
              if (['رغبة', 'Wants', 'Want'].includes(exp.type)) type = ExpenseType.WANT;
              else if (['ادخار واستثمار', 'Savings', 'Saving', 'Investments'].includes(exp.type)) type = ExpenseType.SAVING;
