            <Bot size={24} />
          </div>
          <div>
            <h3 className="font-bold text-lg">{t.advisorStep}</h3>
            <p className="text-xs text-emerald-100 opacity-90">AI Auditor Mode 🤖</p>
          </div>
        </div>
        <button 
          onClick={handleSkip}
          disabled={isSkipping}
          className={`text-xs bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1 ${isSkipping ? 'opacity-70 cursor-wait' : ''}`}
        >
          {isSkipping ? (
             <>
               <Loader2 size={14} className="animate-spin" />
               {lang === 'ar' ? 'جاري الحفظ...' : 'Saving...'}
             </>
          ) : (
             <>
               {t.skipToExpenses}
               {isRtl ? <ArrowLeft size={14} /> : <ArrowRight size={14} />}
             </>
          )}
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm flex flex-col gap-2 ${
                msg.sender === 'user' 
                  ? 'bg-emerald-600 text-white rounded-br-none' 
                  : (msg.isError ? 'bg-red-50 text-red-800 border border-red-100' : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none')
              }`}
            >
               <div className="flex items-start gap-2">
                   {msg.isError && <AlertTriangle size={16} className="mt-0.5 shrink-0" />}
                   <span className="whitespace-pre-wrap">{msg.text}</span>
               </div>
               {msg.isAuthError && (window as any).aistudio && (
                   <button onClick={handleUpdateKey} className="mt-2 bg-red-100 text-red-800 text-xs font-bold py-2 px-3 rounded-lg flex items-center gap-2 w-fit">
                       <Key size={14} /> {lang === 'ar' ? "تحديث المفتاح" : "Update Key"}
                   </button>
               )}
            </div>
          </div>
        ))}

        {(isTyping || isSkipping) && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-gray-200 text-gray-500 px-4 py-2 rounded-full text-xs rounded-bl-none flex items-center gap-2">
              {isSkipping 
                ? (lang === 'ar' ? 'جاري حفظ البيانات التي تم جمعها...' : 'Saving collected data...') 
                : (lang === 'ar' ? 'جاري التفكير 🤔...' : 'Thinking 🤔...')}
            </div>
          </div>
        )}

        {/* Quick Replies / Chips */}
        {quickReplies.length > 0 && !isTyping && !isSkipping && (
          <div className="flex flex-wrap gap-2 mt-2 animate-fade-in">
            {quickReplies.map((reply, idx) => (
              <button
                key={idx}
                onClick={() => handleSend(reply.value)}
                className="bg-white border border-emerald-200 text-emerald-700 hover:bg-emerald-50 px-4 py-2 rounded-full text-sm font-medium transition-all shadow-sm hover:scale-105 active:scale-95"
              >
                {reply.label}
              </button>
            ))}
          </div>
        )}

        {isFinished && !isSkipping && (
           <div className="flex justify-center mt-4 pb-4 animate-fade-in">
              <button
                onClick={onFinish}
                className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-bold shadow-lg hover:bg-emerald-700 hover:scale-105 transition-all flex items-center gap-2"
              >
                <CheckCircle2 size={20} />
                {lang === 'ar' ? "اعتماد الخطة والمتابعة" : "Approve Plan & Continue"}
              </button>
           </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      {!isFinished && !isSkipping && (
        <div className="p-4 bg-white border-t border-gray-100">
          <div className="flex gap-2 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend(input)}
              placeholder={t.chatPlaceholder}
              disabled={isTyping || quickReplies.length > 0} 
              className="flex-1 bg-gray-100 text-gray-800 placeholder-gray-400 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 focus:bg-white transition-all outline-none disabled:bg-gray-50 disabled:cursor-not-allowed"
            />
            <button 
              onClick={() => handleSend(input)}
              disabled={!input.trim() || isTyping}
              className={`p-3 rounded-xl transition-all shadow-md ${
                !input.trim() || isTyping 
                ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                : 'bg-emerald-600 text-white hover:bg-emerald-700 hover:scale-105 active:scale-95'
              }`}
            >
              <Send size={20} className={isRtl ? 'rotate-180' : ''} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { Send, Bot, ArrowRight, ArrowLeft, AlertTriangle, Key, CheckCircle2, Loader2 } from 'lucide-react';
import { Expense, ExpenseType, Language, BudgetRule } from '../types';
import { TRANSLATIONS } from '../constants';

interface FinancialAdvisorProps {
  salary: number;
  onAddExpense: (expense: Omit<Expense, 'id'>) => void;
  onUpdateRule: (rule: BudgetRule) => void;
  onFinish: () => void;
  lang: Language;
}

interface Message {
  id: string;
  sender: 'ai' | 'user';
  text: string;
  isError?: boolean;
  isAuthError?: boolean;
}

interface QuickReply {
  label: string;
  value: string;
}

export const FinancialAdvisor: React.FC<FinancialAdvisorProps> = ({ 
  salary, 
  onAddExpense, 
  onUpdateRule, 
  onFinish, 
  lang 
}) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isSkipping, setIsSkipping] = useState(false);
  const [quickReplies, setQuickReplies] = useState<QuickReply[]>([]);
  const [isFinished, setIsFinished] = useState(false);
  const [retryTrigger, setRetryTrigger] = useState(0);

  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, quickReplies]);

  useEffect(() => {
    const initChat = async () => {
      setMessages([]);
      setQuickReplies([]);
      setIsFinished(false);

      if (!process.env.API_KEY) {
         setMessages([{
             id: 'error-missing',
             sender: 'ai',
             text: lang === 'ar' 
               ? "مفتاح API غير متوفر. يرجى تحديد مفتاح صالح." 
               : "API Key is missing. Please select a valid key.",
             isError: true,
             isAuthError: true
         }]);
         return;
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Comprehensive list with DEFINITIONS
        const EXPENSE_DEFINITIONS = {
            "التمويل العقاري": "القسط الشهري لسداد قرض شراء أو بناء مسكن.",
            "التمويل الشخصي": "القسط الشهري لسداد قرض شخصي تم الحصول عليه سابقا.",
            "قسط السيارة": "الدفعة الشهرية المستحقة لتمويل شراء سيارة.",
            "مصاريف المنزل اليومية": "الإنفاق الشهري المخصص للاحتياجات اليومية للمنزل مثل السوبرماركت والمنظفات.",
            "المصروف المدرسي": "التكاليف الشهرية لإجمالي المبالغ اليوميه التي يتم إعطاؤها للأبناء خلال يومهم الدراسي.",
            "فاتورة الكهرباء": "المبلغ الشهري المستحق مقابل استهلاك الكهرباء.",
            "فاتورة المياه": "المبلغ الشهري المستحق مقابل استهلاك المياه.",
            "فاتورة الجوال والإنترنت": "التكلفة الشهرية لخدمات الهاتف المحمول والإنترنت المنزلي أو الشخصي.",
            "المواصلات": "الإنفاق الشهري على وسائل التنقل غير الوقود مثل التاكسي أو النقل العام.",
            "وقود السيارة": "التكلفة الشهرية للوقود المستخدم للسيارة.",
            "مصروفات طبية وعلاجية": "متوسط الإنفاق الشهري على العلاج، الأدوية، أو الزيارات الطبية.",
            "صيانة وإصلاحات المنزل": "التكاليف الشهرية المخصصة للصيانة الدورية أو إصلاحات المنزل الطارئة.",

            "العاملة المنزلية": "المبلغ الشهري المدفوع مقابل خدمات عاملة أو خادمة منزلية بشكل منتظم.",
            "دروس خصوصية": "التكاليف الشهرية للدروس التعليمية المدفوعة خارج المدرسة للأبناء أو للبالغين.",
            "مشتريات الأبناء": "المصاريف الشهرية المرتبطة باحتياجات الأبناء غير الدراسية مثل الملابس، الألعاب، والأنشطة.",
            "المطاعم والكافيهات": "المبالغ الشهرية المصروفة على الأكل والشرب خارج المنزل.",
            "مصاريف ترفيه وتسوق": "الإنفاق الشهري على التسوق والترفيه مثل التسوق في المولات، الهوايات، والرحلات القصيرة.",
            "الصدقة": "المبالغ الشهرية التي يتم تخصيصها للتبرع بشكل منتظم لأغراض خيرية أو دينية.",
            "الاشتراكات الشهرية": "اجمالي تكلفة الاشتراكات الشهرية مثل منصات البحث عن وظائف، النوادي، التطبيقات، أو الخدمات المدفوعة.",
            "المصروف الشخصي": "المبلغ الشهري الذي يستخدمه المستخدم نفسه لنفقاته الشخصية غير المصنفة.",
            "غسيل السيارة": "المبالغ المصروفة شهريا على تنظيف السيارة.",
            "غسيل المنزل الخارجي": "التكلفة الشهرية لتنظيف الواجهات أو المساحات الخارجية للمنزل.",
            "هدية الوالدة": "المبلغ الشهري المخصص للوالدة.",
            "هدية الزوجة": "المبلغ الشهري المخصص للزوجة.",

            "ادخار عام للطوارئ": "مبلغ شهري يتم تخصيصه لمواجهة الحالات الطارئة والغير متوقعة.",
            "الادخار للعيد القادم": "مبلغ شهري يتم ادخاره لتغطية تكاليف العيد القادم.",
            "ادخار تعليمي للأبناء": "مبلغ شهري مخصص لادخار إجمالي الرسوم الدراسية السنوية للأبناء.",
            "الاستثمار": "مبالغ يتم تخصيصها شهريا للاستثمار في أصول أو أدوات مالية بهدف النمو."
        };

        const checklistJSON = JSON.stringify(EXPENSE_DEFINITIONS);

        const systemInstruction = `
          Context: User Salary = ${salary} ${t.currency}. Language: ${lang === 'ar' ? 'Arabic' : 'English'}.

          ROLE:
          You are "Qawam's Financial Advisor" (المستشار المالي من قوام) 🤖. 
          Style: **Calm, Gentle, Flexible, and Friendly**. Avoid robotic or overly strict phrasing. Use a conversational tone.

          **CORE OBJECTIVE:**
          Perform a structured interview to capture the user's monthly expenses. You must iterate through the provided list of expenses one by one.

          **CRITICAL RULE:**
          When asking about an expense, you MUST weave the specific definition provided in the checklist below into your question naturally and smoothly. 
          - Do NOT label it as "Definition:". 
          - Instead, use phrases like "which is...", "meaning...", "this refers to...".
          - Make the question sound natural, like a human advisor asking a client.

          **THE CHECKLIST (Item: Definition):**
          ${checklistJSON}

          **STRICT INTERVIEW LOGIC:**
          1. **Sequential Check:** Pick an item from the Checklist (Start with major debts/loans, then bills, then living expenses, wants, then savings).
          2. **State 1 (Ask & Explain):** Ask the user if they have this expense in a gentle way.
             *   YOU MUST include the definition in your question naturally.
             *   **Arabic Example**: "هل لديك التزام بـ **'التمويل العقاري'**؟ وهو القسط الشهري الذي يهدف الى سداد القرض العقاري سواء شراء أو بناء مسكن."
             *   **English Example**: "Do you have a **'Mortgage'**? This refers to the monthly installment for buying or building a home."
             *   Options: ["Yes ✅", "No ❌"].
          3. **State 2 (Amount):** IF YES -> Ask "What is the exact monthly amount?" politely -> Options: [] (User must type).
          4. **State 3 (Next):** IF NO -> Move immediately to the next item in the list.

          **FINAL ANALYSIS:**
          Only after iterating through the comprehensive list, determine the rule based on the data collected:
          - Needs > 60% -> Suggest 70/20/10.
          - Needs 45-60% -> Suggest 60/20/20.
          - Needs < 45% -> Suggest 50/30/20.

          OUTPUT FORMAT (JSON ONLY):
          {
            "message": "Question text (natural and including definition)...",
            "options": ["Yes ✅", "No ❌"] (OR empty array [] if asking for amount)
          }

          Final JSON Format (When list is exhausted):
          {
            "message": "Final analysis text...",
            "isFinal": true,
            "rule": { "needs": 60, "wants": 20, "savings": 20 },
            "expenses": [ 
               { "name": "التمويل العقاري", "amount": 3000, "type": "احتياج" },
               ...
            ]
          }
        `;

        const chat = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            systemInstruction: systemInstruction,
            temperature: 0.1, 
          },
        });

        chatSessionRef.current = chat;

        setIsTyping(true);
        const response = await chat.sendMessage({ message: "Start the interview. Ask about the first item with its definition." });
        processResponse(response);

      } catch (error: any) {
        console.error("Failed to init chat", error);

        let msgText = lang === 'ar' ? "فشل تهيئة المستشار المالي." : "Failed to initialize Financial Consultant.";
        const errorStr = typeof error === 'string' ? error : (error.message || JSON.stringify(error));

        // Check for Quota Exceeded (429 / RESOURCE_EXHAUSTED)
        if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED") || errorStr.toLowerCase().includes("quota")) {
            msgText = lang === 'ar' 
                ? "⚠️ عذراً، تم تجاوز حد الاستخدام المجاني للذكاء الاصطناعي حالياً. يمكنك استخدام زر 'تخطي للإدخال اليدوي' في الأعلى لإكمال بياناتك بنفسك."
                : "⚠️ Sorry, AI quota exceeded. Please use the 'Skip to Manual Entry' button above to continue manually.";
        }

        setMessages([{
             id: 'init-error',
             sender: 'ai',
             text: msgText,
             isError: true
        }]);
        setIsTyping(false);
      }
    };

    initChat();
  }, [salary, lang, t.currency, retryTrigger]);

  const cleanAndParseJSON = (rawText: string) => {
    // Improved JSON Extraction:
    // 1. Remove markdown code blocks
    let jsonStr = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();

    // 2. Extract strictly from the first '{' to the last '}' to handle potential trailing artifacts (e.g. `}_`)
    const firstBrace = jsonStr.indexOf('{');
    const lastBrace = jsonStr.lastIndexOf('}');

    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
        jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
    }

    return JSON.parse(jsonStr);
  };

  const processData = (data: any) => {
    if (data.isFinal) {
        setQuickReplies([]);
        setIsFinished(true);

        if (data.rule) onUpdateRule(data.rule);
        if (data.expenses && Array.isArray(data.expenses)) {
             data.expenses.forEach((exp: any) => {
              let type: ExpenseType = ExpenseType.NEED;

              // Map AI response type to Enum
              if (['رغبة', 'Wants', 'Want'].includes(exp.type)) type = ExpenseType.WANT;
              else if (['ادخار واستثمار', 'Savings', 'Saving', 'Investments'].includes(exp.type)) type = ExpenseType.SAVING;
              else type = ExpenseType.NEED;

              onAddExpense({
                name: exp.name,
                amount: typeof exp.amount === 'number' ? exp.amount : parseFloat(exp.amount),
                type: type,
                notes: 'AI Auditor Plan 🤖'
              });
            });
        }
      } else if (data.options && Array.isArray(data.options)) {
        setQuickReplies(data.options.map((opt: string) => ({ label: opt, value: opt })));
      } else {
        setQuickReplies([]); 
      }
  };

  const processResponse = (response: GenerateContentResponse) => {
    setIsTyping(false);
    const rawText = response.text || "";

    try {
      const data = cleanAndParseJSON(rawText);

      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        sender: 'ai', 
        text: data.message 
      }]);

      processData(data);

    } catch (e) {
      console.error("JSON Parse Error", e, rawText);
      setMessages(prev => [...prev, { id: Date.now().toString(), sender: 'ai', text: rawText }]);
    }
  };

  const handleSend = async (text: string) => {
    if (!text.trim() || !chatSessionRef.current) return;

    const userMsg: Message = { id: Date.now().toString(), sender: 'user', text: text };
    setMessages(prev => [...prev, userMsg]);
    setQuickReplies([]);
    setInput('');
    setIsTyping(true);

    try {
      const response = await chatSessionRef.current.sendMessage({ message: text });
      processResponse(response);
    } catch (error: any) {
      console.error("Chat Error:", error);
      setIsTyping(false);

      let errorMsg = lang === 'ar' ? "عذراً، حدث خطأ في الاتصال." : "Sorry, connection error.";
      let isAuthError = false;
      let detailedMsg = error.message || "";
      let isQuotaError = false;

      // Extract details
      const rawErrorStr = typeof error === 'string' ? error : (error.message || JSON.stringify(error));

      // Check for Quota Exceeded (429 / RESOURCE_EXHAUSTED)
      if (rawErrorStr.includes("429") || rawErrorStr.includes("RESOURCE_EXHAUSTED") || rawErrorStr.toLowerCase().includes("quota")) {
          isQuotaError = true;
      }

      if (typeof detailedMsg === 'string' && detailedMsg.includes('{')) {
          try {
             const jsonPart = detailedMsg.substring(detailedMsg.indexOf('{'));
             const errObj = JSON.parse(jsonPart);
             if (errObj.error && errObj.error.message) detailedMsg = errObj.error.message;
          } catch (e) { /* ignore */ }
      }

      if (detailedMsg.includes("API key not valid") || detailedMsg.includes("API_KEY_INVALID")) {
          errorMsg = lang === 'ar' ? "مفتاح API غير صالح." : "Invalid API Key.";
          isAuthError = true;
      } else if (isQuotaError) {
          errorMsg = lang === 'ar' 
            ? "⚠️ عذراً، تم تجاوز حد الاستخدام المجاني للذكاء الاصطناعي. يرجى المتابعة يدوياً عبر زر 'تخطي'."
            : "⚠️ Daily AI quota exceeded. Please use 'Skip to Manual Entry' to continue.";
      }

      setMessages(prev => [...prev, { 
          id: Date.now().toString(), 
          sender: 'ai', 
          text: errorMsg,
          isError: true,
          isAuthError: isAuthError 
      }]);
    }
  };

  const handleSkip = async () => {
    if (!chatSessionRef.current || messages.length <= 1) {
        onFinish();
        return;
    }

    setIsSkipping(true);

    try {
        const response = await chatSessionRef.current.sendMessage({
            message: "The user wants to skip. STOP interview. Generate Final JSON with ONLY the expenses collected SO FAR. Set isFinal=true."
        });

        const rawText = response.text || "";
        const data = cleanAndParseJSON(rawText);

        // Process data (add expenses) but do not update messages state necessarily as we are leaving
        if (data && data.expenses) {
             processData(data);
        }

    } catch (e) {
        console.error("Skip summarization failed", e);
    } finally {
        // Short delay to allow state updates if any
        setTimeout(() => {
            onFinish();
        }, 500);
    }
  };

  const handleUpdateKey = async () => {
      const win = window as any;
      if (win.aistudio) {
          try {
              await win.aistudio.openSelectKey();
              setMessages([]);
              setRetryTrigger(prev => prev + 1); 
          } catch(e) { console.error(e); }
      }
  };

  return (
    <div className="flex flex-col h-[650px] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden animate-fade-in relative">
      {/* Header */}
      <div className="bg-gradient-to-r from-emerald-600 to-teal-600 p-4 text-white flex justify-between items-center shadow-md z-10">
        <div className="flex items-center gap-3">
          <div className="bg-white/20 p-2 rounded-full">
            <Bot size={24} />
          </div>
          <div>
            <h3 className="font-bold text-lg">{t.advisorStep}</h3>
            <p className="text-xs text-emerald-100 opacity-90">AI Auditor Mode 🤖</p>
          </div>
        </div>
        <button 
          onClick={handleSkip}
          disabled={isSkipping}
          className={`text-xs bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1 ${isSkipping ? 'opacity-70 cursor-wait' : ''}`}
        >
          {isSkipping ? (
             <>
               <Loader2 size={14} className="animate-spin" />
               {lang === 'ar' ? 'جاري الحفظ...' : 'Saving...'}
             </>
          ) : (
             <>
               {t.skipToExpenses}
               {isRtl ? <ArrowLeft size={14} /> : <ArrowRight size={14} />}
             </>
          )}
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm flex flex-col gap-2 ${
                msg.sender === 'user' 
                  ? 'bg-emerald-600 text-white rounded-br-none' 
                  : (msg.isError ? 'bg-red-50 text-red-800 border border-red-100' : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none')
              }`}
            >
               <div className="flex items-start gap-2">
                   {msg.isError && <AlertTriangle size={16} className="mt-0.5 shrink-0" />}
                   <span className="whitespace-pre-wrap">{msg.text}</span>
               </div>
               {msg.isAuthError && (window as any).aistudio && (
                   <button onClick={handleUpdateKey} className="mt-2 bg-red-100 text-red-800 text-xs font-bold py-2 px-3 rounded-lg flex items-center gap-2 w-fit">
                       <Key size={14} /> {lang === 'ar' ? "تحديث المفتاح" : "Update Key"}
                   </button>
               )}
            </div>
          </div>
        ))}

        {(isTyping || isSkipping) && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-gray-200 text-gray-500 px-4 py-2 rounded-full text-xs rounded-bl-none flex items-center gap-2">
              {isSkipping 
                ? (lang === 'ar' ? 'جاري حفظ البيانات التي تم جمعها...' : 'Saving collected data...') 
                : (lang === 'ar' ? 'جاري التفكير 🤔...' : 'Thinking 🤔...')}
            </div>
          </div>
        )}

        {/* Quick Replies / Chips */}
        {quickReplies.length > 0 && !isTyping && !isSkipping && (
          <div className="flex flex-wrap gap-2 mt-2 animate-fade-in">
            {quickReplies.map((reply, idx) => (
              <button
                key={idx}
                onClick={() => handleSend(reply.value)}
                className="bg-white border border-emerald-200 text-emerald-700 hover:bg-emerald-50 px-4 py-2 rounded-full text-sm font-medium transition-all shadow-sm hover:scale-105 active:scale-95"
              >
                {reply.label}
              </button>
            ))}
          </div>
        )}

        {isFinished && !isSkipping && (
           <div className="flex justify-center mt-4 pb-4 animate-fade-in">
              <button
                onClick={onFinish}
                className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-bold shadow-lg hover:bg-emerald-700 hover:scale-105 transition-all flex items-center gap-2"
              >
                <CheckCircle2 size={20} />
                {lang === 'ar' ? "اعتماد الخطة والمتابعة" : "Approve Plan & Continue"}
              </button>
           </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      {!isFinished && !isSkipping && (
        <div className="p-4 bg-white border-t border-gray-100">
          <div className="flex gap-2 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend(input)}
              placeholder={t.chatPlaceholder}
              disabled={isTyping || quickReplies.length > 0} 
              className="flex-1 bg-gray-100 text-gray-800 placeholder-gray-400 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 focus:bg-white transition-all outline-none disabled:bg-gray-50 disabled:cursor-not-allowed"
            />
            <button 
              onClick={() => handleSend(input)}
              disabled={!input.trim() || isTyping}
              className={`p-3 rounded-xl transition-all shadow-md ${
                !input.trim() || isTyping 
                ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                : 'bg-emerald-600 text-white hover:bg-emerald-700 hover:scale-105 active:scale-95'
              }`}
            >
              <Send size={20} className={isRtl ? 'rotate-180' : ''} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export enum ExpenseType {
  NEED = 'احتياج',
  WANT = 'رغبة',
  SAVING = 'ادخار واستثمار'
