}

import React, { useState } from 'react';
import { ArrowRight, ArrowLeft, Check, X, Wallet, Info } from 'lucide-react';
import { EXPENSE_DEFINITIONS, TRANSLATIONS, EXPENSE_MAPPING, EXPENSE_MAPPING_EN } from '../constants';
import { Expense, ExpenseType, Language } from '../types';

interface ExpenseWizardProps {
  onComplete: (expenses: Omit<Expense, 'id'>[]) => void;
  lang: Language;
  salary: number;
}

export const ExpenseWizard: React.FC<ExpenseWizardProps> = ({ onComplete, lang, salary }) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  // Convert definitions to array
  const checklistItems = Object.entries(EXPENSE_DEFINITIONS);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [collectedExpenses, setCollectedExpenses] = useState<Omit<Expense, 'id'>[]>([]);
  const [currentAmount, setCurrentAmount] = useState<string>('');
  const [showInput, setShowInput] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);

  const currentItem = checklistItems[currentIndex];
  const progress = ((currentIndex) / checklistItems.length) * 100;

  const handleNext = (hasExpense: boolean) => {
    if (hasExpense) {
      setShowInput(true);
    } else {
      advanceSlide();
    }
  };

  const confirmAmount = () => {
    if (!currentAmount || parseFloat(currentAmount) <= 0) return;

    const amount = parseFloat(currentAmount);
    const name = currentItem[0];

    // Auto categorize
    let type = ExpenseType.NEED;
    if (lang === 'ar' && EXPENSE_MAPPING[name]) type = EXPENSE_MAPPING[name];
    else if (lang === 'en' && EXPENSE_MAPPING_EN[name]) type = EXPENSE_MAPPING_EN[name];

    const newExpense = {
      name: name,
      amount: amount,
      type: type,
      notes: 'Manual Wizard Entry'
    };

    setCollectedExpenses(prev => [...prev, newExpense]);
    advanceSlide();
  };

  const advanceSlide = () => {
    setIsAnimating(true);
    setTimeout(() => {
      if (currentIndex < checklistItems.length - 1) {
        setCurrentIndex(prev => prev + 1);
        setCurrentAmount('');
        setShowInput(false);
      } else {
        // Finish
        onComplete(collectedExpenses);
      }
      setIsAnimating(false);
    }, 300);
  };

  const handleSkipAll = () => {
      onComplete(collectedExpenses);
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[500px] w-full max-w-2xl mx-auto animate-fade-in px-4">

      {/* Progress Bar */}
      <div className="w-full h-2 bg-gray-100 rounded-full mb-8 overflow-hidden">
        <div 
          className="h-full bg-emerald-500 transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        />
      </div>

      <div className={`bg-white rounded-3xl shadow-xl border border-gray-100 p-8 w-full relative transition-all duration-300 transform ${isAnimating ? 'opacity-0 translate-x-10' : 'opacity-100 translate-x-0'}`}>

        {/* Item Count Badge */}
        <div className="absolute top-6 left-6 text-xs font-bold text-gray-300 bg-gray-50 px-2 py-1 rounded-full">
           {currentIndex + 1} / {checklistItems.length}
        </div>

        {/* Question Section */}
        <div className="text-center mt-4">
          <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <Wallet size={32} />
          </div>

          <h3 className="text-2xl font-bold text-gray-800 mb-3">
            {lang === 'ar' ? 'هل لديك مصروف:' : 'Do you have:'}
            <span className="text-blue-600 block mt-1">{currentItem[0]}</span>
          </h3>

          <div className="flex items-center justify-center gap-2 text-gray-500 bg-gray-50 p-3 rounded-xl text-sm mb-8 mx-auto max-w-md">
            <Info size={16} className="shrink-0 text-blue-400" />
            <p>{currentItem[1]}</p>
          </div>

          {!showInput ? (
            <div className="grid grid-cols-2 gap-4 max-w-sm mx-auto">
              <button
                onClick={() => handleNext(false)}
                className="flex items-center justify-center gap-2 py-4 rounded-xl border-2 border-gray-100 hover:border-red-100 hover:bg-red-50 text-gray-600 hover:text-red-600 font-bold transition-all"
              >
                <X size={20} />
                {lang === 'ar' ? 'لا' : 'No'}
              </button>
              <button
                onClick={() => handleNext(true)}
                className="flex items-center justify-center gap-2 py-4 rounded-xl bg-blue-600 hover:bg-blue-700 text-white font-bold shadow-lg shadow-blue-200 transition-all hover:-translate-y-1"
              >
                <Check size={20} />
                {lang === 'ar' ? 'نعم' : 'Yes'}
              </button>
            </div>
          ) : (
            <div className="max-w-xs mx-auto animate-fade-in">
              <label className="block text-start text-xs font-bold text-gray-500 mb-2">
                {lang === 'ar' ? 'أدخل المبلغ الشهري' : 'Enter monthly amount'}
              </label>
              <div className="relative mb-4">
                <input
                  type="number"
                  value={currentAmount}
                  onChange={(e) => setCurrentAmount(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && confirmAmount()}
                  autoFocus
                  placeholder="0"
                  className="w-full text-2xl font-bold border-2 border-blue-100 rounded-xl px-4 py-3 focus:border-blue-500 focus:ring-4 focus:ring-blue-50/50 outline-none transition-all text-center"
                />
                <span className={`absolute top-4 text-gray-400 font-bold ${isRtl ? 'left-4' : 'right-4'}`}>{t.currency}</span>
              </div>
              <button
                onClick={confirmAmount}
                disabled={!currentAmount}
                className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
                  currentAmount 
                  ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200 hover:bg-emerald-700' 
                  : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                }`}
              >
                {lang === 'ar' ? 'تأكيد ومتابعة' : 'Confirm & Next'}
                {isRtl ? <ArrowLeft size={18} /> : <ArrowRight size={18} />}
              </button>
               <button
                onClick={() => setShowInput(false)}
                className="mt-3 text-xs text-gray-400 hover:text-gray-600 underline"
              >
                {lang === 'ar' ? 'رجوع' : 'Back'}
              </button>
            </div>
          )}
        </div>
      </div>

      <div className="mt-8 flex justify-between w-full max-w-2xl px-2">
         <div className="text-xs text-gray-400 font-medium">
             {lang === 'ar' ? `الراتب: ${salary.toLocaleString()}` : `Salary: ${salary.toLocaleString()}`}
         </div>
         <button 
           onClick={handleSkipAll}
           className="text-xs text-gray-400 hover:text-gray-600 font-bold flex items-center gap-1 transition-colors"
         >
           {t.skipToExpenses}
           {isRtl ? <ArrowLeft size={12} /> : <ArrowRight size={12} />}
         </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { Send, Bot, ArrowRight, ArrowLeft, AlertTriangle, Key, CheckCircle2, Sparkles, PieChart } from 'lucide-react';
import { Expense, ExpenseType, Language, BudgetRule } from '../types';
import { TRANSLATIONS } from '../constants';

interface FinancialAdvisorProps {
  salary: number;
  expenses: Expense[];
  onUpdateRule: (rule: BudgetRule) => void;
  onFinish: () => void;
  lang: Language;
}

interface Message {
  id: string;
  sender: 'ai' | 'user';
  text: string;
  isError?: boolean;
  isAuthError?: boolean;
}

export const FinancialAdvisor: React.FC<FinancialAdvisorProps> = ({ 
  salary, 
  expenses,
  onUpdateRule, 
  onFinish, 
  lang 
}) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [analysisComplete, setAnalysisComplete] = useState(false);
  const [suggestedRule, setSuggestedRule] = useState<BudgetRule | null>(null);
  const [retryTrigger, setRetryTrigger] = useState(0);

  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  useEffect(() => {
    const initAnalysis = async () => {
      setMessages([]);
      setAnalysisComplete(false);

      if (!process.env.API_KEY) {
         setMessages([{
             id: 'error-missing',
             sender: 'ai',
             text: lang === 'ar' 
               ? "مفتاح API غير متوفر. يرجى تحديد مفتاح صالح." 
               : "API Key is missing. Please select a valid key.",
             isError: true,
             isAuthError: true
         }]);
         return;
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        const expensesJSON = JSON.stringify(expenses.map(e => ({ name: e.name, amount: e.amount, type: e.type })));

        const systemInstruction = `
          Context: User Salary = ${salary} ${t.currency}. Language: ${lang === 'ar' ? 'Arabic' : 'English'}.

          ROLE:
          You are "Qawam's Financial Advisor".

          TASK:
          1. Analyze the provided list of expenses.
          2. Calculate the total Needs, Wants, and Savings.
          3. Recommend the BEST budget rule (50/30/20, 60/20/20, or 70/20/10) based on their actual Needs ratio.
          4. Return a JSON response.

          OUTPUT FORMAT (JSON ONLY):
          {
            "analysis_message": "A polite, short summary of their situation (e.g., 'I see your needs are high due to Mortgage...'). Explain WHY you chose the rule.",
            "recommended_rule": { "needs": 60, "wants": 20, "savings": 20 }
          }
        `;

        const chat = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            systemInstruction: systemInstruction,
            temperature: 0.1, 
          },
        });

        chatSessionRef.current = chat;

        setIsTyping(true);
        // Trigger analysis
        const response = await chat.sendMessage({ message: `Here is the user's data: ${expensesJSON}. Analyze and recommend.` });
        processResponse(response);

      } catch (error: any) {
        console.error("Failed to init chat", error);

        let msgText = lang === 'ar' ? "فشل تحليل البيانات." : "Failed to analyze data.";
        const errorStr = typeof error === 'string' ? error : (error.message || JSON.stringify(error));

        if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED") || errorStr.toLowerCase().includes("quota")) {
            msgText = lang === 'ar' 
                ? "⚠️ تم تجاوز حد الاستخدام المجاني. لا تقلق، يمكنك المتابعة للإدخال اليدوي."
                : "⚠️ API Quota Exceeded. You can proceed manually.";
        }

        setMessages([{
             id: 'init-error',
             sender: 'ai',
             text: msgText,
             isError: true
        }]);
        setIsTyping(false);
      }
    };

    initAnalysis();
  }, [salary, expenses, lang, t.currency, retryTrigger]);

  const cleanAndParseJSON = (rawText: string) => {
    let jsonStr = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
    const firstBrace = jsonStr.indexOf('{');
    const lastBrace = jsonStr.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
        jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
    }
    return JSON.parse(jsonStr);
  };

  const processResponse = (response: GenerateContentResponse) => {
    setIsTyping(false);
    const rawText = response.text || "";

    try {
      const data = cleanAndParseJSON(rawText);

      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        sender: 'ai', 
        text: data.analysis_message 
      }]);

      if (data.recommended_rule) {
          setSuggestedRule(data.recommended_rule);
          onUpdateRule(data.recommended_rule);
          setAnalysisComplete(true);
      }

    } catch (e) {
      console.error("JSON Parse Error", e, rawText);
      // Fallback: just show text
      setMessages(prev => [...prev, { id: Date.now().toString(), sender: 'ai', text: rawText }]);
      setAnalysisComplete(true); // Allow finish even if parse fails
    }
  };

  const handleSend = async (text: string) => {
    if (!text.trim() || !chatSessionRef.current) return;

    const userMsg: Message = { id: Date.now().toString(), sender: 'user', text: text };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const response = await chatSessionRef.current.sendMessage({ message: text });
      // Here we just expect text back, not JSON
      setIsTyping(false);
      setMessages(prev => [...prev, { 
          id: Date.now().toString(), 
          sender: 'ai', 
          text: response.text || "" 
      }]);

    } catch (error: any) {
      console.error("Chat Error:", error);
      setIsTyping(false);
      setMessages(prev => [...prev, { 
          id: Date.now().toString(), 
          sender: 'ai', 
          text: lang === 'ar' ? "عذراً، حدث خطأ." : "Sorry, error occurred.",
          isError: true
      }]);
    }
  };

  const handleUpdateKey = async () => {
      const win = window as any;
      if (win.aistudio) {
          try {
              await win.aistudio.openSelectKey();
              setMessages([]);
              setRetryTrigger(prev => prev + 1); 
          } catch(e) { console.error(e); }
      }
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden animate-fade-in relative">
      {/* Header */}
      <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-4 text-white flex justify-between items-center shadow-md z-10">
        <div className="flex items-center gap-3">
          <div className="bg-white/20 p-2 rounded-full">
            <Bot size={24} />
          </div>
          <div>
            <h3 className="font-bold text-lg">{t.advisorStep}</h3>
            <p className="text-xs text-blue-100 opacity-90">AI Analysis Mode 🧠</p>
          </div>
        </div>
        <button 
          onClick={onFinish}
          className="text-xs bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg transition-colors flex items-center gap-1"
        >
          {t.finish}
          {isRtl ? <ArrowLeft size={14} /> : <ArrowRight size={14} />}
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm flex flex-col gap-2 ${
                msg.sender === 'user' 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : (msg.isError ? 'bg-red-50 text-red-800 border border-red-100' : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none')
              }`}
            >
               <div className="flex items-start gap-2">
                   {msg.isError && <AlertTriangle size={16} className="mt-0.5 shrink-0" />}
                   <span className="whitespace-pre-wrap">{msg.text}</span>
               </div>
               {msg.isAuthError && (window as any).aistudio && (
                   <button onClick={handleUpdateKey} className="mt-2 bg-red-100 text-red-800 text-xs font-bold py-2 px-3 rounded-lg flex items-center gap-2 w-fit">
                       <Key size={14} /> {lang === 'ar' ? "تحديث المفتاح" : "Update Key"}
                   </button>
               )}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-gray-200 text-gray-500 px-4 py-2 rounded-full text-xs rounded-bl-none flex items-center gap-2">
               <Sparkles size={14} />
               {lang === 'ar' ? 'جاري تحليل البيانات...' : 'Analyzing data...'}
            </div>
          </div>
        )}

        {analysisComplete && suggestedRule && (
           <div className="animate-fade-in bg-indigo-50 border border-indigo-100 p-4 rounded-xl mt-4">
              <h4 className="font-bold text-indigo-800 mb-2 flex items-center gap-2">
                  <PieChart size={18} />
                  {lang === 'ar' ? "القاعدة المقترحة:" : "Suggested Rule:"}
              </h4>
              <div className="flex gap-2">
                  <span className="bg-white px-3 py-1 rounded shadow-sm text-sm font-mono text-red-600">{suggestedRule.needs}% Needs</span>
                  <span className="bg-white px-3 py-1 rounded shadow-sm text-sm font-mono text-amber-600">{suggestedRule.wants}% Wants</span>
                  <span className="bg-white px-3 py-1 rounded shadow-sm text-sm font-mono text-emerald-600">{suggestedRule.savings}% Savings</span>
              </div>

              <div className="flex justify-center mt-4">
                <button
                    onClick={onFinish}
                    className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-bold shadow-lg hover:bg-indigo-700 hover:scale-105 transition-all flex items-center gap-2 text-sm"
                >
                    <CheckCircle2 size={18} />
                    {lang === 'ar' ? "اعتماد ومشاهدة النتائج" : "Approve & View Results"}
                </button>
              </div>
           </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-gray-100">
        <div className="flex gap-2 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend(input)}
              placeholder={t.chatPlaceholder}
              disabled={isTyping} 
              className="flex-1 bg-gray-100 text-gray-800 placeholder-gray-400 border-0 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all outline-none disabled:bg-gray-50 disabled:cursor-not-allowed"
            />
            <button 
              onClick={() => handleSend(input)}
              disabled={!input.trim() || isTyping}
              className={`p-3 rounded-xl transition-all shadow-md ${
                !input.trim() || isTyping 
                ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                : 'bg-blue-600 text-white hover:bg-blue-700 hover:scale-105 active:scale-95'
              }`}
            >
              <Send size={20} className={isRtl ? 'rotate-180' : ''} />
            </button>
        </div>
      </div>
    </div>
  );
};

