      <div className={`bg-white rounded-3xl shadow-xl border border-gray-100 p-6 md:p-8 w-full relative transition-all duration-300 transform ${isAnimating ? 'opacity-0 translate-x-10' : 'opacity-100 translate-x-0'}`}>

