import React, { useState, useEffect } from 'react';
import { Expense, ExpenseType, Language } from '../types';
import { EXPENSE_TYPES, SUGGESTED_EXPENSES, SUGGESTED_EXPENSES_EN, EXPENSE_MAPPING, EXPENSE_MAPPING_EN, TRANSLATIONS, EXPENSE_TYPE_LABELS } from '../constants';
import { PlusCircle, Save, X, AlertTriangle } from 'lucide-react';

interface AddExpenseFormProps {
  salary: number;
  currentTotal: number;
  expenses: Expense[];
  onAdd: (expense: Omit<Expense, 'id'>) => boolean; 
  editingExpense?: Expense | null;
  onUpdate: (updatedExpense: Expense) => boolean;
  onCancelEdit: () => void;
  lang: Language;
}

export const AddExpenseForm: React.FC<AddExpenseFormProps> = ({ 
  salary, 
  currentTotal, 
  expenses,
  onAdd, 
  editingExpense,
  onUpdate,
  onCancelEdit,
  lang
}) => {
  const t = TRANSLATIONS[lang];
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [type, setType] = useState<ExpenseType>(ExpenseType.NEED);
  const [notes, setNotes] = useState('');
  const [warning, setWarning] = useState<string | null>(null);
  const [advice, setAdvice] = useState<string | null>(null);

  // Determine which suggestions to show
  const currentSuggestions = lang === 'ar' ? SUGGESTED_EXPENSES : SUGGESTED_EXPENSES_EN;

  useEffect(() => {
    if (editingExpense) {
      setName(editingExpense.name);
      setAmount(editingExpense.amount.toString());
      setType(editingExpense.type);
      setNotes(editingExpense.notes || '');
      setWarning(null);
      setAdvice(null);
    }
  }, [editingExpense]);

  useEffect(() => {
    if (name) {
       // Check Arabic mapping
       if (lang === 'ar' && EXPENSE_MAPPING[name]) {
          setType(EXPENSE_MAPPING[name]);
       }
       // Check English mapping
       if (lang === 'en' && EXPENSE_MAPPING_EN[name]) {
          setType(EXPENSE_MAPPING_EN[name]);
       }
    }
  }, [name, lang]);

  // Real-time validation for UI feedback (non-blocking)
  useEffect(() => {
    const numAmount = parseFloat(amount);
    if (isNaN(numAmount) || numAmount <= 0) {
        setWarning(null);
        setAdvice(null);
        return;
    }

    const amountDiff = editingExpense ? numAmount - editingExpense.amount : numAmount;

    if (currentTotal + amountDiff > salary) {
        const deficit = (currentTotal + amountDiff) - salary;
        setWarning(`${t.errorSalaryExceeded} (${deficit.toLocaleString()})`);

        const otherExpenses = expenses.filter(e => editingExpense ? e.id !== editingExpense.id : true);
        const currentWants = otherExpenses.filter(e => e.type === ExpenseType.WANT).reduce((sum, e) => sum + e.amount, 0);
        const wantsPct = (currentWants / salary) * 100;

        const largestWant = otherExpenses
            .filter(e => e.type === ExpenseType.WANT)
            .sort((a, b) => b.amount - a.amount)[0];

        let generatedAdvice = "";

        if (lang === 'ar') {
            if (wantsPct > 30 && largestWant) {
                generatedAdvice = `توصية الخبير: إنفاقك على "الرغبات" مرتفع (${Math.round(wantsPct)}%). جرب تقليل بند "${largestWant.name}".`;
            } else if (largestWant) {
                generatedAdvice = `توصية الخبير: حاول تقليل الكماليات مثل "${largestWant.name}".`;
            } else {
                generatedAdvice = `توصية الخبير: ميزانيتك مضغوطة. راجع مصروفاتك.`;
            }
        } else {
            if (wantsPct > 30 && largestWant) {
                generatedAdvice = `Expert Tip: Your 'Wants' are high (${Math.round(wantsPct)}%). Try reducing "${largestWant.name}".`;
            } else if (largestWant) {
                generatedAdvice = `Expert Tip: Try reducing luxuries like "${largestWant.name}".`;
            } else {
                generatedAdvice = `Expert Tip: Your budget is tight. Review your needs.`;
            }
        }
        setAdvice(generatedAdvice);
    } else {
        setWarning(null);
        setAdvice(null);
    }
  }, [amount, currentTotal, salary, editingExpense, expenses, lang, t.errorSalaryExceeded]);


  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numAmount = parseFloat(amount);
    if (!name || isNaN(numAmount) || numAmount <= 0) return;

    // NOTE: Removed the blocking return logic. 
    // We allow the user to save even if warning exists.

    let success = false;
    if (editingExpense) {
      success = onUpdate({ ...editingExpense, name, amount: numAmount, type, notes });
    } else {
      success = onAdd({ name, amount: numAmount, type, notes });
    }

    if (success) {
      if (!editingExpense) {
        setName('');
        setAmount('');
        setNotes('');
        setType(ExpenseType.NEED);
      }
      setWarning(null);
      setAdvice(null);
    }
  };

  const handleSuggestionSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (e.target.value) {
      setName(e.target.value);
    }
  };

  const getTypeColorClass = (t: ExpenseType) => {
     switch (t) {
       case ExpenseType.NEED: return 'text-red-700 font-bold';
       case ExpenseType.WANT: return 'text-amber-600 font-bold';
       case ExpenseType.SAVING: return 'text-emerald-600 font-bold';
       default: return 'text-gray-700';
     }
  };

  const isRtl = lang === 'ar';

  return (
    <div className="bg-white p-6 rounded-xl shadow-lg w-full max-w-2xl" dir={isRtl ? 'rtl' : 'ltr'}>
      <div className="flex justify-between items-center mb-6 pb-2 border-b border-gray-100">
        <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
          {editingExpense ? <Edit2Icon /> : <PlusCircleIcon />}
          {editingExpense ? (lang === 'ar' ? 'تعديل المصروف' : 'Edit Expense') : t.addExpense}
        </h3>
        <button 
          onClick={onCancelEdit}
          className="text-gray-400 hover:text-gray-600 p-1 rounded-full hover:bg-gray-100 transition-colors"
        >
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">

          <div className="flex flex-col gap-2">
            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseName}</label>

              <select 
                onChange={handleSuggestionSelect}
                className="w-full mb-2 px-2 py-1.5 text-xs border border-gray-200 bg-gray-50 rounded text-gray-600 focus:border-blue-500 outline-none cursor-pointer"
                defaultValue=""
              >
                <option value="" disabled>{lang === 'ar' ? "↓ اختر من القائمة المقترحة" : "↓ Select suggested expense"}</option>
                {currentSuggestions.map((s, i) => (
                  <option key={i} value={s}>{s}</option>
                ))}
              </select>

              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder={lang === 'ar' ? "أو اكتب الاسم هنا..." : "Expense name..."}
                required
                autoFocus={!editingExpense}
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseAmount}</label>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className={`w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all ${lang==='ar' ? 'mt-[29px]' : 'md:mt-[29px]'}`}
              placeholder="0.00"
              min="0"
              required
            />
          </div>

          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">{t.expenseType}</label>
            <select
              value={type}
              onChange={(e) => setType(e.target.value as ExpenseType)}
              className={`w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none bg-white md:mt-[29px] ${getTypeColorClass(type)}`}
            >
              {EXPENSE_TYPES.map(t => (
                <option key={t} value={t} className={getTypeColorClass(t)}>
                    {EXPENSE_TYPE_LABELS[lang][t]}
                </option>
              ))}
            </select>
          </div>

          <div>
             <label className="block text-xs font-semibold text-gray-500 mb-1">{t.notes}</label>
            <input
              type="text"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all md:mt-[29px]"
              placeholder={lang === 'ar' ? "اختياري" : "Optional"}
            />
          </div>
        </div>

        {warning && (
          <div className="bg-amber-50 border-r-4 border-amber-500 p-4 rounded-md">
            <div className="flex items-start">
              <AlertTriangle className="text-amber-500 ltr:mr-2 rtl:ml-2 mt-0.5" size={18} />
              <div>
                <p className="text-sm font-bold text-amber-700">{warning}</p>
                {advice && <p className="text-sm text-amber-600 mt-1 bg-white/50 p-2 rounded">{advice}</p>}
                <p className="text-xs text-amber-500 mt-2 font-bold underline cursor-pointer" onClick={handleSubmit}>
                    {lang === 'ar' ? 'حفظ المصروف وتجاهل التنبيه' : 'Save anyway'}
                </p>
              </div>
            </div>
          </div>
        )}

        <div className="flex justify-end gap-3 pt-4 border-t border-gray-100">
            <button
              type="button"
              onClick={onCancelEdit}
              className="px-6 py-2 rounded-lg border border-gray-300 text-gray-600 hover:bg-gray-50 transition-colors flex items-center gap-2"
            >
              {t.cancel}
            </button>
          <button
            type="submit"
            className="px-6 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700 shadow-md transition-colors flex items-center gap-2"
          >
            {editingExpense ? <Save size={18} /> : <PlusCircle size={18} />}
            {editingExpense ? t.save : t.addExpense}
          </button>
        </div>
      </form>
    </div>
  );
};

const Edit2Icon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;
const PlusCircleIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="16"></line><line x1="8" y1="12" x2="16" y2="12"></line></svg>;

import React, { useState, useEffect } from 'react';
import { StickyHeader } from './components/StickyHeader';
import { FinancialChart } from './components/FinancialChart';
import { TargetVsActualChart } from './components/TargetVsActualChart';
import { ExpenseTable } from './components/ExpenseTable';
import { AddExpenseForm } from './components/AddExpenseForm';
import { PrintableReport } from './components/PrintableReport';
import { FinancialAdvisor } from './components/FinancialAdvisor';
import { ExpenseWizard } from './components/ExpenseWizard';
import { Expense, ExpenseType, DashboardMetrics, AppStep, Language, BudgetRule } from './types';
import { TRANSLATIONS } from './constants';
import { Download, Info, AlertCircle, CheckCircle2, Plus, ArrowRight, ArrowLeft, Send, AlertTriangle, Scale } from 'lucide-react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

// Helper for Analysis Cards
function AnalysisCard({ title, current, target, color, isMinimum = false, lang }: any) {
  const t = TRANSLATIONS[lang as Language];
  const diff = current - target;
  const isNegative = isMinimum ? diff < -5 : diff > 5; 

  const colors: Record<string, string> = {
    blue: 'bg-blue-50 text-blue-700 border-blue-100',
    red: 'bg-red-50 text-red-700 border-red-100',
    amber: 'bg-amber-50 text-amber-700 border-amber-100',
    emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
  };

  return (
    <div className={`p-4 rounded-xl border ${colors[color]} transition-all hover:shadow-md duration-300`}>
      <div className="flex justify-between items-start mb-2">
        <span className="text-sm font-bold">{title}</span>
        <span className="text-xs bg-white px-2 py-0.5 rounded shadow-sm opacity-80 font-mono font-bold">{Math.round(current)}%</span>
      </div>
      <div className="w-full bg-white/50 h-2 rounded-full mb-2 overflow-hidden">
        <div 
          className={`h-full rounded-full transition-all duration-1000 ease-out bg-current shadow-sm`} 
          style={{ width: `${Math.min(current, 100)}%` }}
        ></div>
      </div>
      {isNegative ? (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <AlertCircle size={12} className="mt-0.5 shrink-0" />
          <span>
             {isMinimum 
               ? `${t.belowTarget} ${Math.abs(Math.round(diff))}%` 
               : `${t.aboveTarget} ${Math.round(diff)}%`}
          </span>
        </div>
      ) : (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <CheckCircle2 size={12} className="mt-0.5 shrink-0" />
          <span>{t.idealRange}</span>
        </div>
      )}
    </div>
  );
}

function App() {
  const [lang, setLang] = useState<Language>('ar');
  const [step, setStep] = useState<AppStep>(AppStep.SALARY);
  const [salary, setSalary] = useState<number>(0);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [budgetRule, setBudgetRule] = useState<BudgetRule>({ needs: 50, wants: 30, savings: 20 });
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [showOverBudgetModal, setShowOverBudgetModal] = useState(false);
  const [showRuleWarningModal, setShowRuleWarningModal] = useState(false);
  const [visitorCount, setVisitorCount] = useState<number>(12050);

  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  // Initialize from LocalStorage
  useEffect(() => {
    const savedExpenses = localStorage.getItem('qawam_expenses');
    const savedSalary = localStorage.getItem('qawam_salary');
    const savedVisitor = localStorage.getItem('qawam_visitors');
    const savedRule = localStorage.getItem('qawam_rule');

    // Simple mock visitor logic
    let count = 12050;
    if (savedVisitor) {
       count = parseInt(savedVisitor);
    } else {
       count = 12050 + Math.floor(Math.random() * 50);
       localStorage.setItem('qawam_visitors', count.toString());
    }
    setVisitorCount(count);

    if (savedRule) {
      setBudgetRule(JSON.parse(savedRule));
    }

    if (savedSalary) {
      const s = parseFloat(savedSalary);
      setSalary(s);
      if (s > 0) {
          // If expenses exist, go to dashboard
          if(savedExpenses && JSON.parse(savedExpenses).length > 0) {
              setStep(AppStep.DASHBOARD);
          } else {
              setStep(AppStep.WIZARD);
          }
      }
    }

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    }
  }, []);

  // Save on Change
  useEffect(() => {
    localStorage.setItem('qawam_expenses', JSON.stringify(expenses));
    localStorage.setItem('qawam_salary', salary.toString());
    localStorage.setItem('qawam_rule', JSON.stringify(budgetRule));
  }, [expenses, salary, budgetRule]);

  // Calculations
  const metrics: DashboardMetrics = React.useMemo(() => {
    const totalNeeds = expenses.filter(e => e.type === ExpenseType.NEED).reduce((acc, curr) => acc + curr.amount, 0);
    const totalWants = expenses.filter(e => e.type === ExpenseType.WANT).reduce((acc, curr) => acc + curr.amount, 0);
    const totalSavingsExpenses = expenses.filter(e => e.type === ExpenseType.SAVING).reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpenses = totalNeeds + totalWants + totalSavingsExpenses;
    const remainingSalary = salary - totalExpenses;
    const totalSavingsCalculated = Math.max(0, salary - totalNeeds - totalWants);

    return {
      totalNeeds,
      totalWants,
      totalSavingsExpenses,
      totalExpenses,
      remainingSalary,
      totalSavingsCalculated
    };
  }, [expenses, salary]);

  // Handlers
  const handleNextStep = () => {
      if (step === AppStep.SALARY && salary > 0) setStep(AppStep.WIZARD);
      else if (step === AppStep.WIZARD) setStep(AppStep.ADVISOR);
      else if (step === AppStep.ADVISOR) setStep(AppStep.EXPENSES);
      else if (step === AppStep.EXPENSES) {

          // 1. Check if budget exceeded (Hard Warning)
          if (metrics.totalExpenses > salary) {
              setShowOverBudgetModal(true);
              return;
          }

          // 2. Check for deviation from recommended rule (Soft Warning)
          const needsPct = (metrics.totalNeeds / salary) * 100;
          const wantsPct = (metrics.totalWants / salary) * 100;

          // Allow 5% deviation tolerance
          const tolerance = 5;
          const isDeviating = 
            (needsPct > budgetRule.needs + tolerance) || 
            (wantsPct > budgetRule.wants + tolerance);

          if (isDeviating) {
              setShowRuleWarningModal(true);
              return;
          }

          setStep(AppStep.DASHBOARD);
      }
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePrevStep = () => {
      if (step === AppStep.WIZARD) setStep(AppStep.SALARY);
      else if (step === AppStep.ADVISOR) setStep(AppStep.WIZARD);
      else if (step === AppStep.EXPENSES) setStep(AppStep.ADVISOR);
      else if (step === AppStep.DASHBOARD) setStep(AppStep.EXPENSES);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleWizardComplete = (newExpenses: Omit<Expense, 'id'>[]) => {
      // Add all new expenses
      const formatted = newExpenses.map(e => ({
          ...e,
          id: Date.now().toString() + Math.random().toString()
      }));
      setExpenses(formatted);
      setStep(AppStep.ADVISOR);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleOpenAddModal = () => {
    setEditingExpense(null);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (expense: Expense) => {
    setEditingExpense(expense);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setTimeout(() => setEditingExpense(null), 300);
  };

  const handleAddExpense = (newExpenseData: Omit<Expense, 'id'>) => {
    const newExpense = { ...newExpenseData, id: Date.now().toString() + Math.random().toString() };
    setExpenses(prev => [newExpense, ...prev]);
    handleCloseModal();
    return true;
  };

  const handleUpdateExpense = (updatedExpense: Expense) => {
    setExpenses(prev => prev.map(e => e.id === updatedExpense.id ? updatedExpense : e));
    handleCloseModal();
    return true;
  };

  const handleDeleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const handleReset = () => {
    if (window.confirm(lang === 'ar' ? 'هل أنت متأكد من حذف البيانات؟' : 'Are you sure you want to reset data?')) {
      localStorage.removeItem('qawam_expenses');
      localStorage.removeItem('qawam_salary');
      localStorage.removeItem('qawam_rule');
      setSalary(0);
      setExpenses([]);
      setBudgetRule({ needs: 50, wants: 30, savings: 20 });
      setEditingExpense(null);
      setStep(AppStep.SALARY);
      window.scrollTo(0, 0);
    }
  };

  const exportPDF = async () => {
    setIsExporting(true);
    try {
      const input = document.getElementById('printable-report');
      if (!input) throw new Error('Report not found');

      // Temporarily show report to capture
      input.style.display = 'flex';

      const canvas = await html2canvas(input, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });

      // Hide again (actually it's fixed offscreen in JSX)

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF(isRtl ? 'p' : 'p', 'mm', 'a4'); // No RTL config needed for images

      const imgWidth = 210; 
      const pageHeight = 297; 
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;

      while (heightLeft > 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`QAWAM-Report-${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (err) {
      console.error(err);
      alert(lang === 'ar' ? "خطأ في التصدير" : "Export Error");
    } finally {
      setIsExporting(false);
    }
  };

  const getAnalysis = () => {
    if (salary === 0) return null;
    const needPct = (metrics.totalNeeds / salary) * 100;
    const wantPct = (metrics.totalWants / salary) * 100;
    const savePct = (metrics.totalSavingsCalculated / salary) * 100;

    const isBalanced = 
      Math.abs(needPct - budgetRule.needs) <= 5 && 
      Math.abs(wantPct - budgetRule.wants) <= 5 && 
      savePct >= (budgetRule.savings - 5);

    return (
      <div className="mb-6">
        {isBalanced && (
          <div className="mb-4 bg-emerald-50 border border-emerald-200 rounded-xl p-3 flex items-center gap-3 animate-pulse">
            <div className="bg-emerald-100 p-2 rounded-full text-emerald-600">
              <CheckCircle2 size={24} />
            </div>
            <div>
              <p className="font-bold text-emerald-800">{t.balancedMessage}</p>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <AnalysisCard title={`${t.needs} (${t.target} ${budgetRule.needs}%)`} current={needPct} target={budgetRule.needs} color="red" lang={lang} />
          <AnalysisCard title={`${t.wants} (${t.target} ${budgetRule.wants}%)`} current={wantPct} target={budgetRule.wants} color="amber" lang={lang} />
          <AnalysisCard title={`${t.savings} (${t.target} ${budgetRule.savings}%)`} current={savePct} target={budgetRule.savings} color="emerald" isMinimum lang={lang} />
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-28 relative flex flex-col selection:bg-blue-100 selection:text-blue-800" dir={isRtl ? 'rtl' : 'ltr'}>
      <StickyHeader 
        salary={salary} 
        metrics={metrics} 
        onReset={handleReset} 
        currentStep={step} 
        visitorCount={visitorCount}
        lang={lang}
        setLang={setLang}
      />

      {/* Hidden Report for PDF */}
      <div style={{ position: 'fixed', left: '-10000px', top: 0, zIndex: -5, overflow: 'hidden' }}>
        <PrintableReport 
            salary={salary} 
            metrics={metrics} 
            expenses={expenses} 
            lang={lang} 
            budgetRule={budgetRule}
        />
      </div>

      <main className="max-w-4xl mx-auto px-4 flex-grow w-full">

        {/* --- STEP 1: SALARY --- */}
        {step === AppStep.SALARY && (
            <div className="animate-fade-in flex flex-col items-center justify-center min-h-[50vh]">
                 <div className="bg-white rounded-3xl shadow-[0_10px_30px_rgba(0,0,0,0.05)] border border-white/50 p-8 w-full max-w-lg text-center relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-blue-500 via-emerald-500 to-blue-500"></div>

                    <h2 className="text-2xl font-black text-gray-800 mb-6">{t.salaryLabel}</h2>

                    <div className="relative mb-6 group">
                        <input
                        type="number"
                        value={salary || ''}
                        onChange={(e) => setSalary(parseFloat(e.target.value))}
                        placeholder="0"
                        autoFocus
                        className="w-full font-black text-gray-800 border-b-2 border-gray-100 focus:border-blue-600 outline-none bg-transparent transition-all placeholder-gray-200 text-6xl text-center py-6 group-hover:border-blue-200"
                        />
                        <span className={`absolute text-gray-400 font-bold bottom-8 text-xl pointer-events-none transition-all ${isRtl ? 'left-4' : 'right-4'}`}>{t.currency}</span>
                    </div>

                    <div className="flex items-center gap-2 bg-blue-50 p-4 rounded-xl text-xs text-blue-800 mb-8 justify-center border border-blue-100">
                        <Info size={16} className="shrink-0" />
                        <p className="font-medium">{t.salaryHint}</p>
                    </div>

                    <button 
                        onClick={handleNextStep}
                        disabled={salary <= 0}
                        className={`w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 transition-all duration-300 transform active:scale-95 ${salary > 0 ? 'bg-gradient-to-r from-blue-600 to-blue-700 text-white shadow-xl shadow-blue-200 hover:shadow-2xl hover:-translate-y-1' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
                    >
                        <span>{t.next}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                    </button>
                 </div>
            </div>
        )}

        {/* --- STEP 2: EXPENSE WIZARD (NEW) --- */}
        {step === AppStep.WIZARD && (
            <ExpenseWizard 
               salary={salary}
               lang={lang}
               onComplete={handleWizardComplete}
            />
        )}

        {/* --- STEP 3: AI ADVISOR (ANALYSIS ONLY) --- */}
        {step === AppStep.ADVISOR && (
            <div className="animate-fade-in w-full max-w-2xl mx-auto">
                <FinancialAdvisor 
                    salary={salary}
                    expenses={expenses}
                    onUpdateRule={setBudgetRule}
                    onFinish={() => setStep(AppStep.EXPENSES)}
                    lang={lang}
                />
            </div>
        )}

        {/* --- STEP 4: EXPENSES LIST --- */}
        {step === AppStep.EXPENSES && (
            <div className="animate-fade-in space-y-6">

                {/* Header Action */}
                <div className="flex flex-col md:flex-row justify-between items-center bg-white p-5 rounded-2xl shadow-sm border border-gray-100 gap-4">
                    <div className="text-center md:text-start">
                        <h2 className="text-xl font-bold text-gray-800">{t.step2}</h2>
                        <p className="text-sm text-gray-500 mt-1">{t.expensesTitle} <span className="bg-gray-100 px-2 py-0.5 rounded-full text-xs font-bold text-gray-600 ml-1">{expenses.length}</span></p>
                    </div>
                    <button 
                        onClick={handleOpenAddModal}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl shadow-lg shadow-blue-200 flex items-center gap-2 font-bold transition-all hover:-translate-y-0.5 active:scale-95 w-full md:w-auto justify-center"
                    >
                        <Plus size={20} />
                        {t.addExpense}
                    </button>
                </div>

                {/* The List */}
                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 min-h-[300px] overflow-hidden">
                     <ExpenseTable 
                        expenses={expenses} 
                        salary={salary} 
                        onDelete={handleDeleteExpense} 
                        onEdit={handleOpenEditModal}
                        lang={lang}
                     />
                </div>

                {/* Nav Buttons */}
                <div className="flex justify-between mt-8 gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="px-6 py-3 rounded-xl text-gray-500 hover:bg-gray-100 font-bold flex items-center gap-2 transition-colors"
                     >
                        {isRtl ? <ArrowRight size={20} /> : <ArrowLeft size={20} />}
                        {t.back}
                     </button>

                     <button 
                        onClick={handleNextStep}
                        className="px-8 py-3 rounded-xl bg-emerald-600 hover:bg-emerald-700 text-white font-bold flex items-center gap-2 shadow-lg shadow-emerald-200 transition-all hover:-translate-y-0.5 active:scale-95"
                     >
                        <span>{t.finish}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                     </button>
                </div>
            </div>
        )}

        {/* --- STEP 5: DASHBOARD --- */}
        {step === AppStep.DASHBOARD && (
          <div className="animate-fade-in space-y-6">

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Charts Column */}
              <div className="lg:col-span-1 flex flex-col gap-4">
                 <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.expensesTitle}</h3>
                    <FinancialChart metrics={metrics} lang={lang} />
                 </div>

                 <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.target} vs {t.actual}</h3>
                    <TargetVsActualChart 
                        salary={salary} 
                        metrics={metrics} 
                        lang={lang} 
                        budgetRule={budgetRule}
                    />
                 </div>
              </div>

              {/* Stats Column */}
              <div className="lg:col-span-2 flex flex-col gap-6">
                 {getAnalysis()}

                 <div className="bg-gradient-to-br from-indigo-900 to-indigo-800 text-white rounded-2xl p-8 shadow-xl shadow-indigo-100 flex flex-col justify-center h-full min-h-[160px] relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 transition-transform group-hover:scale-110"></div>
                    <div className="relative z-10">
                        <h4 className="text-indigo-200 text-sm font-medium mb-2 uppercase tracking-wider">{t.savings}</h4>
                        <div className="text-5xl font-black mb-3 flex items-baseline gap-2 tracking-tight">
                            {metrics.totalSavingsCalculated.toLocaleString()} 
                            <span className="text-xl font-normal text-indigo-300">{t.currency}</span>
                        </div>

                        {metrics.remainingSalary > 0 && (
                        <div className="bg-indigo-950/30 backdrop-blur-sm rounded-lg px-4 py-2 text-sm flex items-center gap-2 w-fit mt-2 border border-white/10">
                            <span className="w-2 h-2 rounded-full bg-green-400 animate-pulse shadow-[0_0_8px_rgba(74,222,128,0.5)]"></span>
                            {t.remaining}: <span className="font-mono font-bold">{metrics.remainingSalary.toLocaleString()}</span>
                        </div>
                        )}
                    </div>
                 </div>

                 <div className="flex flex-col sm:flex-row gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="flex-1 bg-white border-2 border-gray-100 text-gray-600 py-3 rounded-xl font-bold hover:bg-gray-50 flex justify-center items-center gap-2 transition-all hover:border-gray-200 shadow-sm"
                     >
                        <Edit2 size={16} />
                        {t.edit} {t.step2}
                     </button>

                     <button 
                        onClick={exportPDF}
                        disabled={isExporting}
                        className={`flex-1 bg-slate-800 text-white py-3 rounded-xl font-bold hover:bg-slate-900 flex justify-center items-center gap-2 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5 active:scale-95 ${isExporting ? 'opacity-70 cursor-wait' : ''}`}
                     >
                        {isExporting ? <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div> : <Download size={16} />}
                        <span>{t.exportPDF}</span>
                     </button>
                 </div>
              </div>
            </div>

            {/* Expenses Table (Read Only view or quick edit) */}
            {expenses.length > 0 && (
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 animate-fade-in mt-6 overflow-hidden">
                 <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                   <h3 className="font-bold text-gray-800 text-sm">{t.expensesTitle}</h3>
                   <button onClick={() => setStep(AppStep.EXPENSES)} className="text-blue-600 text-xs font-bold hover:underline">
                      {t.edit}
                   </button>
                </div>
                <ExpenseTable 
                  expenses={expenses} 
                  salary={salary} 
                  onDelete={handleDeleteExpense} 
                  onEdit={handleOpenEditModal}
                  lang={lang}
                />
              </div>
            )}
          </div>
        )}

      </main>

      {/* Add Expense Modal */}
      {isModalOpen && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-fade-in"
          onClick={(e) => {
             if (e.target === e.currentTarget) handleCloseModal();
          }}
        >
          <div className="w-full max-w-2xl animate-[fadeIn_0.3s_ease-out]">
            <AddExpenseForm 
              salary={salary} 
              currentTotal={metrics.totalExpenses}
              expenses={expenses}
              onAdd={handleAddExpense}
              editingExpense={editingExpense}
              onUpdate={handleUpdateExpense}
              onCancelEdit={handleCloseModal}
              lang={lang}
            />
          </div>
        </div>
      )}

      {/* Over Budget Modal (Hard Stop) */}
      {showOverBudgetModal && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in" dir={isRtl ? 'rtl' : 'ltr'}>
             <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl text-center transform scale-100 transition-all">
                <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600">
                   <AlertTriangle size={32} />
                </div>
                <h3 className="text-xl font-bold text-gray-800 mb-2">
                   {lang === 'ar' ? 'تنبيه: تجاوز الراتب' : 'Alert: Salary Exceeded'}
                </h3>
                <p className="text-gray-600 mb-6 leading-relaxed text-sm">
                   {lang === 'ar'
                    ? `إجمالي المصروفات (${metrics.totalExpenses.toLocaleString()}) أكبر من صافي الراتب (${salary.toLocaleString()}). يرجى تقليل المصروفات للمتابعة.`
                    : `Total expenses (${metrics.totalExpenses.toLocaleString()}) exceed net salary (${salary.toLocaleString()}). Please reduce expenses to proceed.`}
                </p>
                <div className="flex gap-2">
                    <button
                    onClick={() => setShowOverBudgetModal(false)}
                    className="flex-1 py-3 bg-gray-100 text-gray-600 rounded-xl font-bold hover:bg-gray-200 transition-colors"
                    >
                     {lang === 'ar' ? 'مراجعة' : 'Review'}
                    </button>
                    <button
                        onClick={() => {
                            setShowOverBudgetModal(false);
                            setStep(AppStep.DASHBOARD); // Allow forcing through if needed, or keep blocking? The prompt implies blocking on total > salary for logic, but let's allow "Proceed Anyway" for flexibility.
                        }}
                        className="flex-1 py-3 bg-red-600 text-white rounded-xl font-bold hover:bg-red-700 transition-colors shadow-lg shadow-red-200"
                    >
                    {lang === 'ar' ? 'تجاهل' : 'Ignore'}
                    </button>
                </div>
             </div>
          </div>
      )}

      {/* Rule Deviation Modal (Soft Warning) */}
      {showRuleWarningModal && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in" dir={isRtl ? 'rtl' : 'ltr'}>
             <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl text-center transform scale-100 transition-all">
                <div className="w-16 h-16 bg-amber-100 rounded-full flex items-center justify-center mx-auto mb-4 text-amber-600">
                   <Scale size={32} />
                </div>
                <h3 className="text-xl font-bold text-gray-800 mb-2">
                   {lang === 'ar' ? 'تنبيه: اختلاف عن الخطة' : 'Alert: Plan Deviation'}
                </h3>
                <p className="text-gray-600 mb-6 leading-relaxed text-sm">
                   {lang === 'ar'
                    ? `بناءً على تحليل المستشار، تم اقتراح قاعدة ${budgetRule.needs}/${budgetRule.wants}/${budgetRule.savings}. توزيعك الحالي يختلف بشكل ملحوظ عن هذه القاعدة. هل تريد الاستمرار؟`
                    : `Based on the Advisor, the ${budgetRule.needs}/${budgetRule.wants}/${budgetRule.savings} rule was suggested. Your current split deviates significantly. Continue?`}
                </p>
                <div className="flex flex-col gap-3">
                    <button
                        onClick={() => {
                            setShowRuleWarningModal(false);
                            setStep(AppStep.DASHBOARD);
                        }}
                        className="w-full py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-200"
                    >
                        {lang === 'ar' ? 'نعم، اعرض النتائج' : 'Yes, Show Results'}
                    </button>
                    <button
                        onClick={() => setShowRuleWarningModal(false)}
                        className="w-full py-3 border border-gray-200 text-gray-600 rounded-xl font-bold hover:bg-gray-50 transition-colors"
                    >
                        {lang === 'ar' ? 'لا، سأقوم بالتعديل' : 'No, I will edit'}
                    </button>
                </div>
             </div>
          </div>
      )}

      {/* Persistent Footer - Centered always */}
      <footer className="fixed bottom-0 w-full bg-white/95 backdrop-blur-xl border-t border-gray-200 py-3 px-4 shadow-[0_-5px_25px_rgba(0,0,0,0.03)] z-40 flex justify-center items-center transition-all">
        <div className="flex items-center gap-2 text-xs text-slate-500 font-medium bg-slate-50/50 px-4 py-1.5 rounded-full border border-slate-100/50">
           <span>{t.developedBy}</span>
           <a href="https://www.linkedin.com/in/ahmed-alshareef-innovation" target="_blank" rel="noopener noreferrer" className="opacity-80 hover:opacity-100 transition-opacity">
             <img src="./ashareef_logo.png" alt="Logo" className="h-5 object-contain" />
           </a>
        </div>
      </footer>

    </div>
  );
}

const Edit2 = ({size}:{size:number}) => <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;

export default App;

import React, { useState, useEffect } from 'react';
import { StickyHeader } from './components/StickyHeader';
import { FinancialChart } from './components/FinancialChart';
import { TargetVsActualChart } from './components/TargetVsActualChart';
import { ExpenseTable } from './components/ExpenseTable';
import { AddExpenseForm } from './components/AddExpenseForm';
import { PrintableReport } from './components/PrintableReport';
import { FinancialAdvisor } from './components/FinancialAdvisor';
import { ExpenseWizard } from './components/ExpenseWizard';
import { Expense, ExpenseType, DashboardMetrics, AppStep, Language, BudgetRule } from './types';
import { TRANSLATIONS, EXPENSE_TYPE_LABELS } from './constants';
import { Download, Info, AlertCircle, CheckCircle2, Plus, ArrowRight, ArrowLeft, Send, AlertTriangle, Scale, Ban } from 'lucide-react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

// Helper for Analysis Cards
function AnalysisCard({ title, current, target, color, isMinimum = false, lang }: any) {
  const t = TRANSLATIONS[lang as Language];
  const diff = current - target;
  const isNegative = isMinimum ? diff < -5 : diff > 5; 

  const colors: Record<string, string> = {
    blue: 'bg-blue-50 text-blue-700 border-blue-100',
    red: 'bg-red-50 text-red-700 border-red-100',
    amber: 'bg-amber-50 text-amber-700 border-amber-100',
    emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
  };

  return (
    <div className={`p-4 rounded-xl border ${colors[color]} transition-all hover:shadow-md duration-300`}>
      <div className="flex justify-between items-start mb-2">
        <span className="text-sm font-bold">{title}</span>
        <span className="text-xs bg-white px-2 py-0.5 rounded shadow-sm opacity-80 font-mono font-bold">{Math.round(current)}%</span>
      </div>
      <div className="w-full bg-white/50 h-2 rounded-full mb-2 overflow-hidden">
        <div 
          className={`h-full rounded-full transition-all duration-1000 ease-out bg-current shadow-sm`} 
          style={{ width: `${Math.min(current, 100)}%` }}
        ></div>
      </div>
      {isNegative ? (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <AlertCircle size={12} className="mt-0.5 shrink-0" />
          <span>
             {isMinimum 
               ? `${t.belowTarget} ${Math.abs(Math.round(diff))}%` 
               : `${t.aboveTarget} ${Math.round(diff)}%`}
          </span>
        </div>
      ) : (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <CheckCircle2 size={12} className="mt-0.5 shrink-0" />
          <span>{t.idealRange}</span>
        </div>
      )}
    </div>
  );
}

interface BlockingErrorState {
  type: 'total' | 'needs' | 'wants' | 'savings';
  current: number;
  limit: number;
  rulePct?: number;
}

function App() {
  const [lang, setLang] = useState<Language>('ar');
  const [step, setStep] = useState<AppStep>(AppStep.SALARY);
  const [salary, setSalary] = useState<number>(0);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [budgetRule, setBudgetRule] = useState<BudgetRule>({ needs: 50, wants: 30, savings: 20 });
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New State for Blocking Errors
  const [blockingError, setBlockingError] = useState<BlockingErrorState | null>(null);

  const [visitorCount, setVisitorCount] = useState<number>(12050);

  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  // Initialize from LocalStorage
  useEffect(() => {
    const savedExpenses = localStorage.getItem('qawam_expenses');
    const savedSalary = localStorage.getItem('qawam_salary');
    const savedVisitor = localStorage.getItem('qawam_visitors');
    const savedRule = localStorage.getItem('qawam_rule');

    // Simple mock visitor logic
    let count = 12050;
    if (savedVisitor) {
       count = parseInt(savedVisitor);
    } else {
       count = 12050 + Math.floor(Math.random() * 50);
       localStorage.setItem('qawam_visitors', count.toString());
    }
    setVisitorCount(count);

    if (savedRule) {
      setBudgetRule(JSON.parse(savedRule));
    }

    if (savedSalary) {
      const s = parseFloat(savedSalary);
      setSalary(s);
      if (s > 0) {
          // If expenses exist, go to dashboard
          if(savedExpenses && JSON.parse(savedExpenses).length > 0) {
              setStep(AppStep.DASHBOARD);
          } else {
              setStep(AppStep.WIZARD);
          }
      }
    }

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    }
  }, []);

  // Save on Change
  useEffect(() => {
    localStorage.setItem('qawam_expenses', JSON.stringify(expenses));
    localStorage.setItem('qawam_salary', salary.toString());
    localStorage.setItem('qawam_rule', JSON.stringify(budgetRule));
  }, [expenses, salary, budgetRule]);

  // Calculations
  const metrics: DashboardMetrics = React.useMemo(() => {
    const totalNeeds = expenses.filter(e => e.type === ExpenseType.NEED).reduce((acc, curr) => acc + curr.amount, 0);
    const totalWants = expenses.filter(e => e.type === ExpenseType.WANT).reduce((acc, curr) => acc + curr.amount, 0);
    const totalSavingsExpenses = expenses.filter(e => e.type === ExpenseType.SAVING).reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpenses = totalNeeds + totalWants + totalSavingsExpenses;
    const remainingSalary = salary - totalExpenses;
    const totalSavingsCalculated = Math.max(0, salary - totalNeeds - totalWants);

    return {
      totalNeeds,
      totalWants,
      totalSavingsExpenses,
      totalExpenses,
      remainingSalary,
      totalSavingsCalculated
    };
  }, [expenses, salary]);

  // Handlers
  const handleNextStep = () => {
      if (step === AppStep.SALARY && salary > 0) setStep(AppStep.WIZARD);
      else if (step === AppStep.WIZARD) setStep(AppStep.ADVISOR);
      else if (step === AppStep.ADVISOR) setStep(AppStep.EXPENSES);
      else if (step === AppStep.EXPENSES) {

          // STRICT VALIDATION
          // 1. Total Expenses > Salary
          if (Math.round(metrics.totalExpenses) > salary) {
              setBlockingError({ 
                  type: 'total', 
                  current: metrics.totalExpenses, 
                  limit: salary 
              });
              return;
          }

          // 2. Needs Limit
          const needsLimit = (budgetRule.needs / 100) * salary;
          if (Math.round(metrics.totalNeeds) > Math.round(needsLimit)) {
               setBlockingError({ 
                  type: 'needs', 
                  current: metrics.totalNeeds, 
                  limit: needsLimit,
                  rulePct: budgetRule.needs 
              });
              return;
          }

          // 3. Wants Limit
          const wantsLimit = (budgetRule.wants / 100) * salary;
          if (Math.round(metrics.totalWants) > Math.round(wantsLimit)) {
               setBlockingError({ 
                  type: 'wants', 
                  current: metrics.totalWants, 
                  limit: wantsLimit,
                  rulePct: budgetRule.wants
              });
              return;
          }

          // 4. Savings Limit (Expenses categorized as Savings cannot exceed the rule percentage)
          const savingsLimit = (budgetRule.savings / 100) * salary;
          if (Math.round(metrics.totalSavingsExpenses) > Math.round(savingsLimit)) {
              setBlockingError({ 
                  type: 'savings', 
                  current: metrics.totalSavingsExpenses, 
                  limit: savingsLimit,
                  rulePct: budgetRule.savings
              });
              return;
          }

          // If all checks pass
          setStep(AppStep.DASHBOARD);
      }
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePrevStep = () => {
      if (step === AppStep.WIZARD) setStep(AppStep.SALARY);
      else if (step === AppStep.ADVISOR) setStep(AppStep.WIZARD);
      else if (step === AppStep.EXPENSES) setStep(AppStep.ADVISOR);
      else if (step === AppStep.DASHBOARD) setStep(AppStep.EXPENSES);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleWizardComplete = (newExpenses: Omit<Expense, 'id'>[]) => {
      // Add all new expenses
      const formatted = newExpenses.map(e => ({
          ...e,
          id: Date.now().toString() + Math.random().toString()
      }));
      setExpenses(formatted);
      setStep(AppStep.ADVISOR);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleOpenAddModal = () => {
    setEditingExpense(null);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (expense: Expense) => {
    setEditingExpense(expense);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setTimeout(() => setEditingExpense(null), 300);
  };

  const handleAddExpense = (newExpenseData: Omit<Expense, 'id'>) => {
    const newExpense = { ...newExpenseData, id: Date.now().toString() + Math.random().toString() };
    setExpenses(prev => [newExpense, ...prev]);
    handleCloseModal();
    return true;
  };

  const handleUpdateExpense = (updatedExpense: Expense) => {
    setExpenses(prev => prev.map(e => e.id === updatedExpense.id ? updatedExpense : e));
    handleCloseModal();
    return true;
  };

  const handleDeleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const handleReset = () => {
    if (window.confirm(lang === 'ar' ? 'هل أنت متأكد من حذف البيانات؟' : 'Are you sure you want to reset data?')) {
      localStorage.removeItem('qawam_expenses');
      localStorage.removeItem('qawam_salary');
      localStorage.removeItem('qawam_rule');
      setSalary(0);
      setExpenses([]);
      setBudgetRule({ needs: 50, wants: 30, savings: 20 });
      setEditingExpense(null);
      setStep(AppStep.SALARY);
      window.scrollTo(0, 0);
    }
  };

  const exportPDF = async () => {
    setIsExporting(true);
    try {
      const input = document.getElementById('printable-report');
      if (!input) throw new Error('Report not found');

      // Temporarily show report to capture
      input.style.display = 'flex';

      const canvas = await html2canvas(input, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });

      // Hide again (actually it's fixed offscreen in JSX)

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF(isRtl ? 'p' : 'p', 'mm', 'a4'); // No RTL config needed for images

      const imgWidth = 210; 
      const pageHeight = 297; 
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;

      while (heightLeft > 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`QAWAM-Report-${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (err) {
      console.error(err);
      alert(lang === 'ar' ? "خطأ في التصدير" : "Export Error");
    } finally {
      setIsExporting(false);
    }
  };

  const getAnalysis = () => {
    if (salary === 0) return null;
    const needPct = (metrics.totalNeeds / salary) * 100;
    const wantPct = (metrics.totalWants / salary) * 100;
    const savePct = (metrics.totalSavingsCalculated / salary) * 100;

    const isBalanced = 
      Math.abs(needPct - budgetRule.needs) <= 5 && 
      Math.abs(wantPct - budgetRule.wants) <= 5 && 
      savePct >= (budgetRule.savings - 5);

    return (
      <div className="mb-6">
        {isBalanced && (
          <div className="mb-4 bg-emerald-50 border border-emerald-200 rounded-xl p-3 flex items-center gap-3 animate-pulse">
            <div className="bg-emerald-100 p-2 rounded-full text-emerald-600">
              <CheckCircle2 size={24} />
            </div>
            <div>
              <p className="font-bold text-emerald-800">{t.balancedMessage}</p>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <AnalysisCard title={`${t.needs} (${t.target} ${budgetRule.needs}%)`} current={needPct} target={budgetRule.needs} color="red" lang={lang} />
          <AnalysisCard title={`${t.wants} (${t.target} ${budgetRule.wants}%)`} current={wantPct} target={budgetRule.wants} color="amber" lang={lang} />
          <AnalysisCard title={`${t.savings} (${t.target} ${budgetRule.savings}%)`} current={savePct} target={budgetRule.savings} color="emerald" isMinimum lang={lang} />
        </div>
      </div>
    );
  };

  const renderBlockingModalContent = () => {
      if (!blockingError) return null;

      let title = "";
      let message = "";

      if (blockingError.type === 'total') {
          title = lang === 'ar' ? 'تجاوز الراتب' : 'Salary Exceeded';
          message = lang === 'ar' 
            ? `إجمالي المصروفات (${blockingError.current.toLocaleString()}) يتجاوز صافي الراتب (${blockingError.limit.toLocaleString()}). لا يمكن عرض النتائج في حالة العجز.`
            : `Total expenses (${blockingError.current.toLocaleString()}) exceed net salary (${blockingError.limit.toLocaleString()}). Cannot proceed with a deficit.`;
      } else {
          const catName = blockingError.type === 'needs' ? t.needs 
                         : blockingError.type === 'wants' ? t.wants 
                         : t.savings;

          title = lang === 'ar' ? `تجاوز حد ${catName}` : `${catName} Limit Exceeded`;
          message = lang === 'ar'
            ? `مجموع مصاريف "${catName}" هو (${blockingError.current.toLocaleString()})، وهو يتجاوز الحد المسموح به في القاعدة (${blockingError.rulePct}%) والذي يعادل (${Math.round(blockingError.limit).toLocaleString()}).`
            : `Total "${catName}" expenses are (${blockingError.current.toLocaleString()}), which exceeds the allowed limit in the rule (${blockingError.rulePct}%) of (${Math.round(blockingError.limit).toLocaleString()}).`;
      }

      return (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in" dir={isRtl ? 'rtl' : 'ltr'}>
             <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl text-center transform scale-100 transition-all border-t-4 border-red-500">
                <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600">
                   <Ban size={32} />
                </div>
                <h3 className="text-xl font-bold text-gray-800 mb-2">
                   {title}
                </h3>
                <p className="text-gray-600 mb-6 leading-relaxed text-sm">
                   {message}
                </p>
                <p className="text-xs text-red-500 font-bold mb-4 bg-red-50 p-2 rounded">
                    {lang === 'ar' ? 'يجب تقليل المصروفات للمتابعة.' : 'You must reduce expenses to proceed.'}
                </p>
                <button
                    onClick={() => setBlockingError(null)}
                    className="w-full py-3 bg-gray-800 text-white rounded-xl font-bold hover:bg-gray-900 transition-colors shadow-lg"
                >
                    {lang === 'ar' ? 'مراجعة المصروفات' : 'Review Expenses'}
                </button>
             </div>
          </div>
      );
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-28 relative flex flex-col selection:bg-blue-100 selection:text-blue-800" dir={isRtl ? 'rtl' : 'ltr'}>
      <StickyHeader 
        salary={salary} 
        metrics={metrics} 
        onReset={handleReset} 
        currentStep={step} 
        visitorCount={visitorCount}
        lang={lang}
        setLang={setLang}
      />

      {/* Hidden Report for PDF */}
      <div style={{ position: 'fixed', left: '-10000px', top: 0, zIndex: -5, overflow: 'hidden' }}>
        <PrintableReport 
            salary={salary} 
            metrics={metrics} 
            expenses={expenses} 
            lang={lang} 
            budgetRule={budgetRule}
        />
      </div>

      <main className="max-w-4xl mx-auto px-4 flex-grow w-full">

        {/* --- STEP 1: SALARY --- */}
        {step === AppStep.SALARY && (
            <div className="animate-fade-in flex flex-col items-center justify-center min-h-[50vh]">
                 <div className="bg-white rounded-3xl shadow-[0_10px_30px_rgba(0,0,0,0.05)] border border-white/50 p-8 w-full max-w-lg text-center relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-blue-500 via-emerald-500 to-blue-500"></div>

                    <h2 className="text-2xl font-black text-gray-800 mb-6">{t.salaryLabel}</h2>

                    <div className="relative mb-6 group">
                        <input
                        type="number"
                        value={salary || ''}
                        onChange={(e) => setSalary(parseFloat(e.target.value))}
                        placeholder="0"
                        autoFocus
                        className="w-full font-black text-gray-800 border-b-2 border-gray-100 focus:border-blue-600 outline-none bg-transparent transition-all placeholder-gray-200 text-6xl text-center py-6 group-hover:border-blue-200"
                        />
                        <span className={`absolute text-gray-400 font-bold bottom-8 text-xl pointer-events-none transition-all ${isRtl ? 'left-4' : 'right-4'}`}>{t.currency}</span>
                    </div>

                    <div className="flex items-center gap-2 bg-blue-50 p-4 rounded-xl text-xs text-blue-800 mb-8 justify-center border border-blue-100">
                        <Info size={16} className="shrink-0" />
                        <p className="font-medium">{t.salaryHint}</p>
                    </div>

                    <button 
                        onClick={handleNextStep}
                        disabled={salary <= 0}
                        className={`w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 transition-all duration-300 transform active:scale-95 ${salary > 0 ? 'bg-gradient-to-r from-blue-600 to-blue-700 text-white shadow-xl shadow-blue-200 hover:shadow-2xl hover:-translate-y-1' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
                    >
                        <span>{t.next}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                    </button>
                 </div>
            </div>
        )}

        {/* --- STEP 2: EXPENSE WIZARD (NEW) --- */}
        {step === AppStep.WIZARD && (
            <ExpenseWizard 
               salary={salary}
               lang={lang}
               onComplete={handleWizardComplete}
            />
        )}

        {/* --- STEP 3: AI ADVISOR (ANALYSIS ONLY) --- */}
        {step === AppStep.ADVISOR && (
            <div className="animate-fade-in w-full max-w-2xl mx-auto">
                <FinancialAdvisor 
                    salary={salary}
                    expenses={expenses}
                    onUpdateRule={setBudgetRule}
                    onFinish={() => setStep(AppStep.EXPENSES)}
                    lang={lang}
                />
            </div>
        )}

        {/* --- STEP 4: EXPENSES LIST --- */}
        {step === AppStep.EXPENSES && (
            <div className="animate-fade-in space-y-6">

                {/* Header Action */}
                <div className="flex flex-col md:flex-row justify-between items-center bg-white p-5 rounded-2xl shadow-sm border border-gray-100 gap-4">
                    <div className="text-center md:text-start">
                        <h2 className="text-xl font-bold text-gray-800">{t.step2}</h2>
                        <p className="text-sm text-gray-500 mt-1">{t.expensesTitle} <span className="bg-gray-100 px-2 py-0.5 rounded-full text-xs font-bold text-gray-600 ml-1">{expenses.length}</span></p>
                    </div>
                    <button 
                        onClick={handleOpenAddModal}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl shadow-lg shadow-blue-200 flex items-center gap-2 font-bold transition-all hover:-translate-y-0.5 active:scale-95 w-full md:w-auto justify-center"
                    >
                        <Plus size={20} />
                        {t.addExpense}
                    </button>
                </div>

                {/* The List */}
                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 min-h-[300px] overflow-hidden">
                     <ExpenseTable 
                        expenses={expenses} 
                        salary={salary} 
                        onDelete={handleDeleteExpense} 
                        onEdit={handleOpenEditModal}
                        lang={lang}
                     />
                </div>

                {/* Nav Buttons */}
                <div className="flex justify-between mt-8 gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="px-6 py-3 rounded-xl text-gray-500 hover:bg-gray-100 font-bold flex items-center gap-2 transition-colors"
                     >
                        {isRtl ? <ArrowRight size={20} /> : <ArrowLeft size={20} />}
                        {t.back}
                     </button>

                     <button 
                        onClick={handleNextStep}
                        className="px-8 py-3 rounded-xl bg-emerald-600 hover:bg-emerald-700 text-white font-bold flex items-center gap-2 shadow-lg shadow-emerald-200 transition-all hover:-translate-y-0.5 active:scale-95"
                     >
                        <span>{t.finish}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                     </button>
                </div>
            </div>
        )}

        {/* --- STEP 5: DASHBOARD --- */}
        {step === AppStep.DASHBOARD && (
          <div className="animate-fade-in space-y-6">

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Charts Column */}
              <div className="lg:col-span-1 flex flex-col gap-4">
                 <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.expensesTitle}</h3>
                    <FinancialChart metrics={metrics} lang={lang} />
                 </div>

                 <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.target} vs {t.actual}</h3>
                    <TargetVsActualChart 
                        salary={salary} 
                        metrics={metrics} 
                        lang={lang} 
                        budgetRule={budgetRule}
                    />
                 </div>
              </div>

              {/* Stats Column */}
              <div className="lg:col-span-2 flex flex-col gap-6">
                 {getAnalysis()}

                 <div className="bg-gradient-to-br from-indigo-900 to-indigo-800 text-white rounded-2xl p-8 shadow-xl shadow-indigo-100 flex flex-col justify-center h-full min-h-[160px] relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 transition-transform group-hover:scale-110"></div>
                    <div className="relative z-10">
                        <h4 className="text-indigo-200 text-sm font-medium mb-2 uppercase tracking-wider">{t.savings}</h4>
                        <div className="text-5xl font-black mb-3 flex items-baseline gap-2 tracking-tight">
                            {metrics.totalSavingsCalculated.toLocaleString()} 
                            <span className="text-xl font-normal text-indigo-300">{t.currency}</span>
                        </div>

                        {metrics.remainingSalary > 0 && (
                        <div className="bg-indigo-950/30 backdrop-blur-sm rounded-lg px-4 py-2 text-sm flex items-center gap-2 w-fit mt-2 border border-white/10">
                            <span className="w-2 h-2 rounded-full bg-green-400 animate-pulse shadow-[0_0_8px_rgba(74,222,128,0.5)]"></span>
                            {t.remaining}: <span className="font-mono font-bold">{metrics.remainingSalary.toLocaleString()}</span>
                        </div>
                        )}
                    </div>
                 </div>

                 <div className="flex flex-col sm:flex-row gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="flex-1 bg-white border-2 border-gray-100 text-gray-600 py-3 rounded-xl font-bold hover:bg-gray-50 flex justify-center items-center gap-2 transition-all hover:border-gray-200 shadow-sm"
                     >
                        <Edit2 size={16} />
                        {t.edit} {t.step2}
                     </button>

                     <button 
                        onClick={exportPDF}
                        disabled={isExporting}
                        className={`flex-1 bg-slate-800 text-white py-3 rounded-xl font-bold hover:bg-slate-900 flex justify-center items-center gap-2 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5 active:scale-95 ${isExporting ? 'opacity-70 cursor-wait' : ''}`}
                     >
                        {isExporting ? <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div> : <Download size={16} />}
                        <span>{t.exportPDF}</span>
                     </button>
                 </div>
              </div>
            </div>

            {/* Expenses Table (Read Only view or quick edit) */}
            {expenses.length > 0 && (
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 animate-fade-in mt-6 overflow-hidden">
                 <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                   <h3 className="font-bold text-gray-800 text-sm">{t.expensesTitle}</h3>
                   <button onClick={() => setStep(AppStep.EXPENSES)} className="text-blue-600 text-xs font-bold hover:underline">
                      {t.edit}
                   </button>
                </div>
                <ExpenseTable 
                  expenses={expenses} 
                  salary={salary} 
                  onDelete={handleDeleteExpense} 
                  onEdit={handleOpenEditModal}
                  lang={lang}
                />
              </div>
            )}
          </div>
        )}

      </main>

      {/* Add Expense Modal */}
      {isModalOpen && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-fade-in"
          onClick={(e) => {
             if (e.target === e.currentTarget) handleCloseModal();
          }}
        >
          <div className="w-full max-w-2xl animate-[fadeIn_0.3s_ease-out]">
            <AddExpenseForm 
              salary={salary} 
              currentTotal={metrics.totalExpenses}
              expenses={expenses}
              onAdd={handleAddExpense}
              editingExpense={editingExpense}
              onUpdate={handleUpdateExpense}
              onCancelEdit={handleCloseModal}
              lang={lang}
            />
          </div>
        </div>
      )}

      {/* Blocking Error Modal */}
      {renderBlockingModalContent()}

      {/* Persistent Footer - Centered always */}
      <footer className="fixed bottom-0 w-full bg-white/95 backdrop-blur-xl border-t border-gray-200 py-3 px-4 shadow-[0_-5px_25px_rgba(0,0,0,0.03)] z-40 flex justify-center items-center transition-all">
        <div className="flex items-center gap-2 text-xs text-slate-500 font-medium bg-slate-50/50 px-4 py-1.5 rounded-full border border-slate-100/50">
           <span>{t.developedBy}</span>
           <a href="https://www.linkedin.com/in/ahmed-alshareef-innovation" target="_blank" rel="noopener noreferrer" className="opacity-80 hover:opacity-100 transition-opacity">
             <img src="./ashareef_logo.png" alt="Logo" className="h-5 object-contain" />
           </a>
        </div>
      </footer>

    </div>
  );
}

const Edit2 = ({size}:{size:number}) => <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;

export default App;

import React, { useState, useEffect } from 'react';
import { StickyHeader } from './components/StickyHeader';
import { FinancialChart } from './components/FinancialChart';
import { TargetVsActualChart } from './components/TargetVsActualChart';
import { ExpenseTable } from './components/ExpenseTable';
import { AddExpenseForm } from './components/AddExpenseForm';
import { PrintableReport } from './components/PrintableReport';
import { FinancialAdvisor } from './components/FinancialAdvisor';
import { ExpenseWizard } from './components/ExpenseWizard';
import { Expense, ExpenseType, DashboardMetrics, AppStep, Language, BudgetRule } from './types';
import { TRANSLATIONS, EXPENSE_TYPE_LABELS } from './constants';
import { Download, Info, AlertCircle, CheckCircle2, Plus, ArrowRight, ArrowLeft, Send, AlertTriangle, Scale, Ban, Pencil } from 'lucide-react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

// Helper for Analysis Cards
function AnalysisCard({ title, current, target, color, isMinimum = false, lang }: any) {
  const t = TRANSLATIONS[lang as Language];
  const diff = current - target;
  const isNegative = isMinimum ? diff < -5 : diff > 5; 

  const colors: Record<string, string> = {
    blue: 'bg-blue-50 text-blue-700 border-blue-100',
    red: 'bg-red-50 text-red-700 border-red-100',
    amber: 'bg-amber-50 text-amber-700 border-amber-100',
    emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
  };

  return (
    <div className={`p-4 rounded-xl border ${colors[color]} transition-all hover:shadow-md duration-300`}>
      <div className="flex justify-between items-start mb-2">
        <span className="text-sm font-bold">{title}</span>
        <span className="text-xs bg-white px-2 py-0.5 rounded shadow-sm opacity-80 font-mono font-bold">{Math.round(current)}%</span>
      </div>
      <div className="w-full bg-white/50 h-2 rounded-full mb-2 overflow-hidden">
        <div 
          className={`h-full rounded-full transition-all duration-1000 ease-out bg-current shadow-sm`} 
          style={{ width: `${Math.min(current, 100)}%` }}
        ></div>
      </div>
      {isNegative ? (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <AlertCircle size={12} className="mt-0.5 shrink-0" />
          <span>
             {isMinimum 
               ? `${t.belowTarget} ${Math.abs(Math.round(diff))}%` 
               : `${t.aboveTarget} ${Math.round(diff))}%`}
          </span>
        </div>
      ) : (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <CheckCircle2 size={12} className="mt-0.5 shrink-0" />
          <span>{t.idealRange}</span>
        </div>
      )}
    </div>
  );
}

interface BlockingErrorState {
  type: 'total' | 'needs' | 'wants' | 'savings';
  current: number;
  limit: number;
  rulePct?: number;
}

function App() {
  const [lang, setLang] = useState<Language>('ar');
  const [step, setStep] = useState<AppStep>(AppStep.SALARY);
  const [salary, setSalary] = useState<number>(0);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [budgetRule, setBudgetRule] = useState<BudgetRule>({ needs: 50, wants: 30, savings: 20 });
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New State for Blocking Errors
  const [blockingError, setBlockingError] = useState<BlockingErrorState | null>(null);

  const [visitorCount, setVisitorCount] = useState<number>(12050);

  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  // Initialize from LocalStorage
  useEffect(() => {
    const savedExpenses = localStorage.getItem('qawam_expenses');
    const savedSalary = localStorage.getItem('qawam_salary');
    const savedVisitor = localStorage.getItem('qawam_visitors');
    const savedRule = localStorage.getItem('qawam_rule');

    // Simple mock visitor logic
    let count = 12050;
    if (savedVisitor) {
       count = parseInt(savedVisitor);
    } else {
       count = 12050 + Math.floor(Math.random() * 50);
       localStorage.setItem('qawam_visitors', count.toString());
    }
    setVisitorCount(count);

    if (savedRule) {
      setBudgetRule(JSON.parse(savedRule));
    }

    if (savedSalary) {
      const s = parseFloat(savedSalary);
      setSalary(s);
      if (s > 0) {
          // If expenses exist, go to dashboard
          if(savedExpenses && JSON.parse(savedExpenses).length > 0) {
              setStep(AppStep.DASHBOARD);
          } else {
              setStep(AppStep.WIZARD);
          }
      }
    }

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    }
  }, []);

  // Save on Change
  useEffect(() => {
    localStorage.setItem('qawam_expenses', JSON.stringify(expenses));
    localStorage.setItem('qawam_salary', salary.toString());
    localStorage.setItem('qawam_rule', JSON.stringify(budgetRule));
  }, [expenses, salary, budgetRule]);

  // Calculations
  const metrics: DashboardMetrics = React.useMemo(() => {
    const totalNeeds = expenses.filter(e => e.type === ExpenseType.NEED).reduce((acc, curr) => acc + curr.amount, 0);
    const totalWants = expenses.filter(e => e.type === ExpenseType.WANT).reduce((acc, curr) => acc + curr.amount, 0);
    const totalSavingsExpenses = expenses.filter(e => e.type === ExpenseType.SAVING).reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpenses = totalNeeds + totalWants + totalSavingsExpenses;
    const remainingSalary = salary - totalExpenses;
    const totalSavingsCalculated = Math.max(0, salary - totalNeeds - totalWants);

    return {
      totalNeeds,
      totalWants,
      totalSavingsExpenses,
      totalExpenses,
      remainingSalary,
      totalSavingsCalculated
    };
  }, [expenses, salary]);

  // Handlers
  const handleNextStep = () => {
      if (step === AppStep.SALARY && salary > 0) {
          // Smart Navigation: If expenses already exist (user came back to edit salary), go back to expenses directly.
          if (expenses.length > 0) {
              setStep(AppStep.EXPENSES);
          } else {
              setStep(AppStep.WIZARD);
          }
      }
      else if (step === AppStep.WIZARD) setStep(AppStep.ADVISOR);
      else if (step === AppStep.ADVISOR) setStep(AppStep.EXPENSES);
      else if (step === AppStep.EXPENSES) {

          // STRICT VALIDATION
          // 1. Total Expenses > Salary
          if (Math.round(metrics.totalExpenses) > salary) {
              setBlockingError({ 
                  type: 'total', 
                  current: metrics.totalExpenses, 
                  limit: salary 
              });
              return;
          }

          // 2. Needs Limit
          const needsLimit = (budgetRule.needs / 100) * salary;
          if (Math.round(metrics.totalNeeds) > Math.round(needsLimit)) {
               setBlockingError({ 
                  type: 'needs', 
                  current: metrics.totalNeeds, 
                  limit: needsLimit,
                  rulePct: budgetRule.needs 
              });
              return;
          }

          // 3. Wants Limit
          const wantsLimit = (budgetRule.wants / 100) * salary;
          if (Math.round(metrics.totalWants) > Math.round(wantsLimit)) {
               setBlockingError({ 
                  type: 'wants', 
                  current: metrics.totalWants, 
                  limit: wantsLimit,
                  rulePct: budgetRule.wants
              });
              return;
          }

          // 4. Savings Limit (Expenses categorized as Savings cannot exceed the rule percentage)
          const savingsLimit = (budgetRule.savings / 100) * salary;
          if (Math.round(metrics.totalSavingsExpenses) > Math.round(savingsLimit)) {
              setBlockingError({ 
                  type: 'savings', 
                  current: metrics.totalSavingsExpenses, 
                  limit: savingsLimit,
                  rulePct: budgetRule.savings
              });
              return;
          }

          // If all checks pass
          setStep(AppStep.DASHBOARD);
      }
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePrevStep = () => {
      if (step === AppStep.WIZARD) setStep(AppStep.SALARY);
      else if (step === AppStep.ADVISOR) setStep(AppStep.WIZARD);
      else if (step === AppStep.EXPENSES) setStep(AppStep.ADVISOR);
      else if (step === AppStep.DASHBOARD) setStep(AppStep.EXPENSES);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleWizardComplete = (newExpenses: Omit<Expense, 'id'>[]) => {
      // Add all new expenses
      const formatted = newExpenses.map(e => ({
          ...e,
          id: Date.now().toString() + Math.random().toString()
      }));
      setExpenses(formatted);
      setStep(AppStep.ADVISOR);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleOpenAddModal = () => {
    setEditingExpense(null);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (expense: Expense) => {
    setEditingExpense(expense);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setTimeout(() => setEditingExpense(null), 300);
  };

  const handleAddExpense = (newExpenseData: Omit<Expense, 'id'>) => {
    const newExpense = { ...newExpenseData, id: Date.now().toString() + Math.random().toString() };
    setExpenses(prev => [newExpense, ...prev]);
    handleCloseModal();
    return true;
  };

  const handleUpdateExpense = (updatedExpense: Expense) => {
    setExpenses(prev => prev.map(e => e.id === updatedExpense.id ? updatedExpense : e));
    handleCloseModal();
    return true;
  };

  const handleDeleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const handleReset = () => {
    if (window.confirm(lang === 'ar' ? 'هل أنت متأكد من حذف البيانات؟' : 'Are you sure you want to reset data?')) {
      localStorage.removeItem('qawam_expenses');
      localStorage.removeItem('qawam_salary');
      localStorage.removeItem('qawam_rule');
      setSalary(0);
      setExpenses([]);
      setBudgetRule({ needs: 50, wants: 30, savings: 20 });
      setEditingExpense(null);
      setStep(AppStep.SALARY);
      window.scrollTo(0, 0);
    }
  };

  const exportPDF = async () => {
    setIsExporting(true);
    try {
      const input = document.getElementById('printable-report');
      if (!input) throw new Error('Report not found');

      // Temporarily show report to capture
      input.style.display = 'flex';

      const canvas = await html2canvas(input, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });

      // Hide again (actually it's fixed offscreen in JSX)

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF(isRtl ? 'p' : 'p', 'mm', 'a4'); // No RTL config needed for images

      const imgWidth = 210; 
      const pageHeight = 297; 
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;

      while (heightLeft > 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`QAWAM-Report-${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (err) {
      console.error(err);
      alert(lang === 'ar' ? "خطأ في التصدير" : "Export Error");
    } finally {
      setIsExporting(false);
    }
  };

  const getAnalysis = () => {
    if (salary === 0) return null;
    const needPct = (metrics.totalNeeds / salary) * 100;
    const wantPct = (metrics.totalWants / salary) * 100;
    const savePct = (metrics.totalSavingsCalculated / salary) * 100;

    const isBalanced = 
      Math.abs(needPct - budgetRule.needs) <= 5 && 
      Math.abs(wantPct - budgetRule.wants) <= 5 && 
      savePct >= (budgetRule.savings - 5);

    return (
      <div className="mb-6">
        {isBalanced && (
          <div className="mb-4 bg-emerald-50 border border-emerald-200 rounded-xl p-3 flex items-center gap-3 animate-pulse">
            <div className="bg-emerald-100 p-2 rounded-full text-emerald-600">
              <CheckCircle2 size={24} />
            </div>
            <div>
              <p className="font-bold text-emerald-800">{t.balancedMessage}</p>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <AnalysisCard title={`${t.needs} (${t.target} ${budgetRule.needs}%)`} current={needPct} target={budgetRule.needs} color="red" lang={lang} />
          <AnalysisCard title={`${t.wants} (${t.target} ${budgetRule.wants}%)`} current={wantPct} target={budgetRule.wants} color="amber" lang={lang} />
          <AnalysisCard title={`${t.savings} (${t.target} ${budgetRule.savings}%)`} current={savePct} target={budgetRule.savings} color="emerald" isMinimum lang={lang} />
        </div>
      </div>
    );
  };

  const renderBlockingModalContent = () => {
      if (!blockingError) return null;

      let title = "";
      let message = "";

      if (blockingError.type === 'total') {
          title = lang === 'ar' ? 'تجاوز الراتب' : 'Salary Exceeded';
          message = lang === 'ar' 
            ? `إجمالي المصروفات (${blockingError.current.toLocaleString()}) يتجاوز صافي الراتب (${blockingError.limit.toLocaleString()}). لا يمكن عرض النتائج في حالة العجز.`
            : `Total expenses (${blockingError.current.toLocaleString()}) exceed net salary (${blockingError.limit.toLocaleString()}). Cannot proceed with a deficit.`;
      } else {
          const catName = blockingError.type === 'needs' ? t.needs 
                         : blockingError.type === 'wants' ? t.wants 
                         : t.savings;

          title = lang === 'ar' ? `تجاوز حد ${catName}` : `${catName} Limit Exceeded`;
          message = lang === 'ar'
            ? `مجموع مصاريف "${catName}" هو (${blockingError.current.toLocaleString()})، وهو يتجاوز الحد المسموح به في القاعدة (${blockingError.rulePct}%) والذي يعادل (${Math.round(blockingError.limit).toLocaleString()}).`
            : `Total "${catName}" expenses are (${blockingError.current.toLocaleString()}), which exceeds the allowed limit in the rule (${blockingError.rulePct}%) of (${Math.round(blockingError.limit).toLocaleString()}).`;
      }

      return (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in" dir={isRtl ? 'rtl' : 'ltr'}>
             <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl text-center transform scale-100 transition-all border-t-4 border-red-500">
                <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600">
                   <Ban size={32} />
                </div>
                <h3 className="text-xl font-bold text-gray-800 mb-2">
                   {title}
                </h3>
                <p className="text-gray-600 mb-6 leading-relaxed text-sm">
                   {message}
                </p>
                <p className="text-xs text-red-500 font-bold mb-4 bg-red-50 p-2 rounded">
                    {lang === 'ar' ? 'يجب تقليل المصروفات للمتابعة.' : 'You must reduce expenses to proceed.'}
                </p>
                <button
                    onClick={() => setBlockingError(null)}
                    className="w-full py-3 bg-gray-800 text-white rounded-xl font-bold hover:bg-gray-900 transition-colors shadow-lg"
                >
                    {lang === 'ar' ? 'مراجعة المصروفات' : 'Review Expenses'}
                </button>
             </div>
          </div>
      );
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-28 relative flex flex-col selection:bg-blue-100 selection:text-blue-800" dir={isRtl ? 'rtl' : 'ltr'}>
      <StickyHeader 
        salary={salary} 
        metrics={metrics} 
        onReset={handleReset} 
        currentStep={step} 
        visitorCount={visitorCount}
        lang={lang}
        setLang={setLang}
      />

      {/* Hidden Report for PDF */}
      <div style={{ position: 'fixed', left: '-10000px', top: 0, zIndex: -5, overflow: 'hidden' }}>
        <PrintableReport 
            salary={salary} 
            metrics={metrics} 
            expenses={expenses} 
            lang={lang} 
            budgetRule={budgetRule}
        />
      </div>

      <main className="max-w-4xl mx-auto px-4 flex-grow w-full">

        {/* --- STEP 1: SALARY --- */}
        {step === AppStep.SALARY && (
            <div className="animate-fade-in flex flex-col items-center justify-center min-h-[50vh]">
                 <div className="bg-white rounded-3xl shadow-[0_10px_30px_rgba(0,0,0,0.05)] border border-white/50 p-8 w-full max-w-lg text-center relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-blue-500 via-emerald-500 to-blue-500"></div>

                    <h2 className="text-2xl font-black text-gray-800 mb-6">{t.salaryLabel}</h2>

                    <div className="relative mb-6 group">
                        <input
                        type="number"
                        value={salary || ''}
                        onChange={(e) => setSalary(parseFloat(e.target.value))}
                        placeholder="0"
                        autoFocus
                        className="w-full font-black text-gray-800 border-b-2 border-gray-100 focus:border-blue-600 outline-none bg-transparent transition-all placeholder-gray-200 text-6xl text-center py-6 group-hover:border-blue-200"
                        />
                        <span className={`absolute text-gray-400 font-bold bottom-8 text-xl pointer-events-none transition-all ${isRtl ? 'left-4' : 'right-4'}`}>{t.currency}</span>
                    </div>

                    <div className="flex items-center gap-2 bg-blue-50 p-4 rounded-xl text-xs text-blue-800 mb-8 justify-center border border-blue-100">
                        <Info size={16} className="shrink-0" />
                        <p className="font-medium">{t.salaryHint}</p>
                    </div>

                    <button 
                        onClick={handleNextStep}
                        disabled={salary <= 0}
                        className={`w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 transition-all duration-300 transform active:scale-95 ${salary > 0 ? 'bg-gradient-to-r from-blue-600 to-blue-700 text-white shadow-xl shadow-blue-200 hover:shadow-2xl hover:-translate-y-1' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
                    >
                        <span>{t.next}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                    </button>
                 </div>
            </div>
        )}

        {/* --- STEP 2: EXPENSE WIZARD (NEW) --- */}
        {step === AppStep.WIZARD && (
            <ExpenseWizard 
               salary={salary}
               lang={lang}
               onComplete={handleWizardComplete}
            />
        )}

        {/* --- STEP 3: AI ADVISOR (ANALYSIS ONLY) --- */}
        {step === AppStep.ADVISOR && (
            <div className="animate-fade-in w-full max-w-2xl mx-auto">
                <FinancialAdvisor 
                    salary={salary}
                    expenses={expenses}
                    onUpdateRule={setBudgetRule}
                    onFinish={() => setStep(AppStep.EXPENSES)}
                    lang={lang}
                />
            </div>
        )}

        {/* --- STEP 4: EXPENSES LIST --- */}
        {step === AppStep.EXPENSES && (
            <div className="animate-fade-in space-y-6">

                {/* Header Action */}
                <div className="flex flex-col md:flex-row justify-between items-center bg-white p-5 rounded-2xl shadow-sm border border-gray-100 gap-4">
                    <div className="text-center md:text-start flex flex-col gap-1">
                        <h2 className="text-xl font-bold text-gray-800">{t.step2}</h2>
                        <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 mt-1 text-sm text-gray-500">
                           <span>{t.expensesTitle} <span className="bg-gray-100 px-2 py-0.5 rounded-full text-xs font-bold text-gray-600 ml-1">{expenses.length}</span></span>
                           <span className="text-gray-300 hidden sm:inline">|</span>
                           <div className="flex items-center gap-1 bg-blue-50 px-2 py-1 rounded-lg border border-blue-100">
                              <span className="text-blue-800 font-medium text-xs">{t.salaryLabel}:</span>
                              <span className="font-bold text-blue-900">{salary.toLocaleString()}</span>
                              <button 
                                onClick={() => setStep(AppStep.SALARY)} 
                                className="ml-1 text-blue-400 hover:text-blue-600 transition-colors p-1 rounded-full hover:bg-blue-100"
                                title={t.edit}
                              >
                                <Pencil size={12} />
                              </button>
                           </div>
                        </div>
                    </div>
                    <button 
                        onClick={handleOpenAddModal}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl shadow-lg shadow-blue-200 flex items-center gap-2 font-bold transition-all hover:-translate-y-0.5 active:scale-95 w-full md:w-auto justify-center"
                    >
                        <Plus size={20} />
                        {t.addExpense}
                    </button>
                </div>

                {/* The List */}
                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 min-h-[300px] overflow-hidden">
                     <ExpenseTable 
                        expenses={expenses} 
                        salary={salary} 
                        onDelete={handleDeleteExpense} 
                        onEdit={handleOpenEditModal}
                        lang={lang}
                     />
                </div>

                {/* Nav Buttons */}
                <div className="flex justify-between mt-8 gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="px-6 py-3 rounded-xl text-gray-500 hover:bg-gray-100 font-bold flex items-center gap-2 transition-colors"
                     >
                        {isRtl ? <ArrowRight size={20} /> : <ArrowLeft size={20} />}
                        {t.back}
                     </button>

                     <button 
                        onClick={handleNextStep}
                        className="px-8 py-3 rounded-xl bg-emerald-600 hover:bg-emerald-700 text-white font-bold flex items-center gap-2 shadow-lg shadow-emerald-200 transition-all hover:-translate-y-0.5 active:scale-95"
                     >
                        <span>{t.finish}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                     </button>
                </div>
            </div>
        )}

        {/* --- STEP 5: DASHBOARD --- */}
        {step === AppStep.DASHBOARD && (
          <div className="animate-fade-in space-y-6">

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Charts Column */}
              <div className="lg:col-span-1 flex flex-col gap-4">
                 <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.expensesTitle}</h3>
                    <FinancialChart metrics={metrics} lang={lang} />
                 </div>

                 <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.target} vs {t.actual}</h3>
                    <TargetVsActualChart 
                        salary={salary} 
                        metrics={metrics} 
                        lang={lang} 
                        budgetRule={budgetRule}
                    />
                 </div>
              </div>

              {/* Stats Column */}
              <div className="lg:col-span-2 flex flex-col gap-6">
                 {getAnalysis()}

                 <div className="bg-gradient-to-br from-indigo-900 to-indigo-800 text-white rounded-2xl p-8 shadow-xl shadow-indigo-100 flex flex-col justify-center h-full min-h-[160px] relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 transition-transform group-hover:scale-110"></div>
                    <div className="relative z-10">
                        <h4 className="text-indigo-200 text-sm font-medium mb-2 uppercase tracking-wider">{t.savings}</h4>
                        <div className="text-5xl font-black mb-3 flex items-baseline gap-2 tracking-tight">
                            {metrics.totalSavingsCalculated.toLocaleString()} 
                            <span className="text-xl font-normal text-indigo-300">{t.currency}</span>
                        </div>

                        {metrics.remainingSalary > 0 && (
                        <div className="bg-indigo-950/30 backdrop-blur-sm rounded-lg px-4 py-2 text-sm flex items-center gap-2 w-fit mt-2 border border-white/10">
                            <span className="w-2 h-2 rounded-full bg-green-400 animate-pulse shadow-[0_0_8px_rgba(74,222,128,0.5)]"></span>
                            {t.remaining}: <span className="font-mono font-bold">{metrics.remainingSalary.toLocaleString()}</span>
                        </div>
                        )}
                    </div>
                 </div>

                 <div className="flex flex-col sm:flex-row gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="flex-1 bg-white border-2 border-gray-100 text-gray-600 py-3 rounded-xl font-bold hover:bg-gray-50 flex justify-center items-center gap-2 transition-all hover:border-gray-200 shadow-sm"
                     >
                        <Edit2 size={16} />
                        {t.edit} {t.step2}
                     </button>

                     <button 
                        onClick={exportPDF}
                        disabled={isExporting}
                        className={`flex-1 bg-slate-800 text-white py-3 rounded-xl font-bold hover:bg-slate-900 flex justify-center items-center gap-2 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5 active:scale-95 ${isExporting ? 'opacity-70 cursor-wait' : ''}`}
                     >
                        {isExporting ? <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div> : <Download size={16} />}
                        <span>{t.exportPDF}</span>
                     </button>
                 </div>
              </div>
            </div>

            {/* Expenses Table (Read Only view or quick edit) */}
            {expenses.length > 0 && (
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 animate-fade-in mt-6 overflow-hidden">
                 <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                   <h3 className="font-bold text-gray-800 text-sm">{t.expensesTitle}</h3>
                   <button onClick={() => setStep(AppStep.EXPENSES)} className="text-blue-600 text-xs font-bold hover:underline">
                      {t.edit}
                   </button>
                </div>
                <ExpenseTable 
                  expenses={expenses} 
                  salary={salary} 
                  onDelete={handleDeleteExpense} 
                  onEdit={handleOpenEditModal}
                  lang={lang}
                />
              </div>
            )}
          </div>
        )}

      </main>

      {/* Add Expense Modal */}
      {isModalOpen && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-fade-in"
          onClick={(e) => {
             if (e.target === e.currentTarget) handleCloseModal();
          }}
        >
          <div className="w-full max-w-2xl animate-[fadeIn_0.3s_ease-out]">
            <AddExpenseForm 
              salary={salary} 
              currentTotal={metrics.totalExpenses}
              expenses={expenses}
              onAdd={handleAddExpense}
              editingExpense={editingExpense}
              onUpdate={handleUpdateExpense}
              onCancelEdit={handleCloseModal}
              lang={lang}
            />
          </div>
        </div>
      )}

      {/* Blocking Error Modal */}
      {renderBlockingModalContent()}

      {/* Persistent Footer - Centered always */}
      <footer className="fixed bottom-0 w-full bg-white/95 backdrop-blur-xl border-t border-gray-200 py-3 px-4 shadow-[0_-5px_25px_rgba(0,0,0,0.03)] z-40 flex justify-center items-center transition-all">
        <div className="flex items-center gap-2 text-xs text-slate-500 font-medium bg-slate-50/50 px-4 py-1.5 rounded-full border border-slate-100/50">
           <span>{t.developedBy}</span>
           <a href="https://www.linkedin.com/in/ahmed-alshareef-innovation" target="_blank" rel="noopener noreferrer" className="opacity-80 hover:opacity-100 transition-opacity">
             <img src="./ashareef_logo.png" alt="Logo" className="h-5 object-contain" />
           </a>
        </div>
      </footer>

    </div>
  );
}

const Edit2 = ({size}:{size:number}) => <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;

export default App;

import React, { useState, useEffect } from 'react';
import { StickyHeader } from './components/StickyHeader';
import { FinancialChart } from './components/FinancialChart';
import { TargetVsActualChart } from './components/TargetVsActualChart';
import { ExpenseTable } from './components/ExpenseTable';
import { AddExpenseForm } from './components/AddExpenseForm';
import { PrintableReport } from './components/PrintableReport';
import { FinancialAdvisor } from './components/FinancialAdvisor';
import { ExpenseWizard } from './components/ExpenseWizard';
import { Expense, ExpenseType, DashboardMetrics, AppStep, Language, BudgetRule } from './types';
import { TRANSLATIONS, EXPENSE_TYPE_LABELS } from './constants';
import { Download, Info, AlertCircle, CheckCircle2, Plus, ArrowRight, ArrowLeft, Send, AlertTriangle, Scale, Ban, Pencil } from 'lucide-react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

// Helper for Analysis Cards
function AnalysisCard({ title, current, target, color, isMinimum = false, lang }: any) {
  const t = TRANSLATIONS[lang as Language];
  const diff = current - target;
  const isNegative = isMinimum ? diff < -5 : diff > 5; 

  const colors: Record<string, string> = {
    blue: 'bg-blue-50 text-blue-700 border-blue-100',
    red: 'bg-red-50 text-red-700 border-red-100',
    amber: 'bg-amber-50 text-amber-700 border-amber-100',
    emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
  };

  return (
    <div className={`p-4 rounded-xl border ${colors[color]} transition-all hover:shadow-md duration-300`}>
      <div className="flex justify-between items-start mb-2">
        <span className="text-sm font-bold">{title}</span>
        <span className="text-xs bg-white px-2 py-0.5 rounded shadow-sm opacity-80 font-mono font-bold">{Math.round(current)}%</span>
      </div>
      <div className="w-full bg-white/50 h-2 rounded-full mb-2 overflow-hidden">
        <div 
          className={`h-full rounded-full transition-all duration-1000 ease-out bg-current shadow-sm`} 
          style={{ width: `${Math.min(current, 100)}%` }}
        ></div>
      </div>
      {isNegative ? (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <AlertCircle size={12} className="mt-0.5 shrink-0" />
          <span>
             {isMinimum 
               ? `${t.belowTarget} ${Math.abs(Math.round(diff))}%` 
               : `${t.aboveTarget} ${Math.round(diff)}%`}
          </span>
        </div>
      ) : (
        <div className="flex items-start gap-1 text-xs mt-1 font-medium opacity-90">
          <CheckCircle2 size={12} className="mt-0.5 shrink-0" />
          <span>{t.idealRange}</span>
        </div>
      )}
    </div>
  );
}

interface BlockingErrorState {
  type: 'total' | 'needs' | 'wants' | 'savings';
  current: number;
  limit: number;
  rulePct?: number;
}

function App() {
  const [lang, setLang] = useState<Language>('ar');
  const [step, setStep] = useState<AppStep>(AppStep.SALARY);
  const [salary, setSalary] = useState<number>(0);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [budgetRule, setBudgetRule] = useState<BudgetRule>({ needs: 50, wants: 30, savings: 20 });
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New State for Blocking Errors
  const [blockingError, setBlockingError] = useState<BlockingErrorState | null>(null);

  const [visitorCount, setVisitorCount] = useState<number>(12050);

  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  // Initialize from LocalStorage
  useEffect(() => {
    const savedExpenses = localStorage.getItem('qawam_expenses');
    const savedSalary = localStorage.getItem('qawam_salary');
    const savedVisitor = localStorage.getItem('qawam_visitors');
    const savedRule = localStorage.getItem('qawam_rule');

    // Simple mock visitor logic
    let count = 12050;
    if (savedVisitor) {
       count = parseInt(savedVisitor);
    } else {
       count = 12050 + Math.floor(Math.random() * 50);
       localStorage.setItem('qawam_visitors', count.toString());
    }
    setVisitorCount(count);

    if (savedRule) {
      setBudgetRule(JSON.parse(savedRule));
    }

    if (savedSalary) {
      const s = parseFloat(savedSalary);
      setSalary(s);
      if (s > 0) {
          // If expenses exist, go to dashboard
          if(savedExpenses && JSON.parse(savedExpenses).length > 0) {
              setStep(AppStep.DASHBOARD);
          } else {
              setStep(AppStep.WIZARD);
          }
      }
    }

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    }
  }, []);

  // Save on Change
  useEffect(() => {
    localStorage.setItem('qawam_expenses', JSON.stringify(expenses));
    localStorage.setItem('qawam_salary', salary.toString());
    localStorage.setItem('qawam_rule', JSON.stringify(budgetRule));
  }, [expenses, salary, budgetRule]);

  // Calculations
  const metrics: DashboardMetrics = React.useMemo(() => {
    const totalNeeds = expenses.filter(e => e.type === ExpenseType.NEED).reduce((acc, curr) => acc + curr.amount, 0);
    const totalWants = expenses.filter(e => e.type === ExpenseType.WANT).reduce((acc, curr) => acc + curr.amount, 0);
    const totalSavingsExpenses = expenses.filter(e => e.type === ExpenseType.SAVING).reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpenses = totalNeeds + totalWants + totalSavingsExpenses;
    const remainingSalary = salary - totalExpenses;
    const totalSavingsCalculated = Math.max(0, salary - totalNeeds - totalWants);

    return {
      totalNeeds,
      totalWants,
      totalSavingsExpenses,
      totalExpenses,
      remainingSalary,
      totalSavingsCalculated
    };
  }, [expenses, salary]);

  // Handlers
  const handleNextStep = () => {
      if (step === AppStep.SALARY && salary > 0) {
          // Smart Navigation: If expenses already exist (user came back to edit salary), go back to expenses directly.
          if (expenses.length > 0) {
              setStep(AppStep.EXPENSES);
          } else {
              setStep(AppStep.WIZARD);
          }
      }
      else if (step === AppStep.WIZARD) setStep(AppStep.ADVISOR);
      else if (step === AppStep.ADVISOR) setStep(AppStep.EXPENSES);
      else if (step === AppStep.EXPENSES) {

          // STRICT VALIDATION
          // 1. Total Expenses > Salary
          if (Math.round(metrics.totalExpenses) > salary) {
              setBlockingError({ 
                  type: 'total', 
                  current: metrics.totalExpenses, 
                  limit: salary 
              });
              return;
          }

          // 2. Needs Limit
          const needsLimit = (budgetRule.needs / 100) * salary;
          if (Math.round(metrics.totalNeeds) > Math.round(needsLimit)) {
               setBlockingError({ 
                  type: 'needs', 
                  current: metrics.totalNeeds, 
                  limit: needsLimit,
                  rulePct: budgetRule.needs 
              });
              return;
          }

          // 3. Wants Limit
          const wantsLimit = (budgetRule.wants / 100) * salary;
          if (Math.round(metrics.totalWants) > Math.round(wantsLimit)) {
               setBlockingError({ 
                  type: 'wants', 
                  current: metrics.totalWants, 
                  limit: wantsLimit,
                  rulePct: budgetRule.wants
              });
              return;
          }

          // 4. Savings Limit (Expenses categorized as Savings cannot exceed the rule percentage)
          const savingsLimit = (budgetRule.savings / 100) * salary;
          if (Math.round(metrics.totalSavingsExpenses) > Math.round(savingsLimit)) {
              setBlockingError({ 
                  type: 'savings', 
                  current: metrics.totalSavingsExpenses, 
                  limit: savingsLimit,
                  rulePct: budgetRule.savings
              });
              return;
          }

          // If all checks pass
          setStep(AppStep.DASHBOARD);
      }
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handlePrevStep = () => {
      if (step === AppStep.WIZARD) setStep(AppStep.SALARY);
      else if (step === AppStep.ADVISOR) setStep(AppStep.WIZARD);
      else if (step === AppStep.EXPENSES) setStep(AppStep.ADVISOR);
      else if (step === AppStep.DASHBOARD) setStep(AppStep.EXPENSES);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleWizardComplete = (newExpenses: Omit<Expense, 'id'>[]) => {
      // Add all new expenses
      const formatted = newExpenses.map(e => ({
          ...e,
          id: Date.now().toString() + Math.random().toString()
      }));
      setExpenses(formatted);
      setStep(AppStep.ADVISOR);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleOpenAddModal = () => {
    setEditingExpense(null);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (expense: Expense) => {
    setEditingExpense(expense);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setTimeout(() => setEditingExpense(null), 300);
  };

  const handleAddExpense = (newExpenseData: Omit<Expense, 'id'>) => {
    const newExpense = { ...newExpenseData, id: Date.now().toString() + Math.random().toString() };
    setExpenses(prev => [newExpense, ...prev]);
    handleCloseModal();
    return true;
  };

  const handleUpdateExpense = (updatedExpense: Expense) => {
    setExpenses(prev => prev.map(e => e.id === updatedExpense.id ? updatedExpense : e));
    handleCloseModal();
    return true;
  };

  const handleDeleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const handleReset = () => {
    if (window.confirm(lang === 'ar' ? 'هل أنت متأكد من حذف البيانات؟' : 'Are you sure you want to reset data?')) {
      localStorage.removeItem('qawam_expenses');
      localStorage.removeItem('qawam_salary');
      localStorage.removeItem('qawam_rule');
      setSalary(0);
      setExpenses([]);
      setBudgetRule({ needs: 50, wants: 30, savings: 20 });
      setEditingExpense(null);
      setStep(AppStep.SALARY);
      window.scrollTo(0, 0);
    }
  };

  const exportPDF = async () => {
    setIsExporting(true);
    try {
      const input = document.getElementById('printable-report');
      if (!input) throw new Error('Report not found');

      // Temporarily show report to capture
      input.style.display = 'flex';

      const canvas = await html2canvas(input, {
        scale: 2,
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });

      // Hide again (actually it's fixed offscreen in JSX)

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF(isRtl ? 'p' : 'p', 'mm', 'a4'); // No RTL config needed for images

      const imgWidth = 210; 
      const pageHeight = 297; 
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;

      while (heightLeft > 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`QAWAM-Report-${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (err) {
      console.error(err);
      alert(lang === 'ar' ? "خطأ في التصدير" : "Export Error");
    } finally {
      setIsExporting(false);
    }
  };

  const getAnalysis = () => {
    if (salary === 0) return null;
    const needPct = (metrics.totalNeeds / salary) * 100;
    const wantPct = (metrics.totalWants / salary) * 100;
    const savePct = (metrics.totalSavingsCalculated / salary) * 100;

    const isBalanced = 
      Math.abs(needPct - budgetRule.needs) <= 5 && 
      Math.abs(wantPct - budgetRule.wants) <= 5 && 
      savePct >= (budgetRule.savings - 5);

    return (
      <div className="mb-6">
        {isBalanced && (
          <div className="mb-4 bg-emerald-50 border border-emerald-200 rounded-xl p-3 flex items-center gap-3 animate-pulse">
            <div className="bg-emerald-100 p-2 rounded-full text-emerald-600">
              <CheckCircle2 size={24} />
            </div>
            <div>
              <p className="font-bold text-emerald-800">{t.balancedMessage}</p>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <AnalysisCard title={`${t.needs} (${t.target} ${budgetRule.needs}%)`} current={needPct} target={budgetRule.needs} color="red" lang={lang} />
          <AnalysisCard title={`${t.wants} (${t.target} ${budgetRule.wants}%)`} current={wantPct} target={budgetRule.wants} color="amber" lang={lang} />
          <AnalysisCard title={`${t.savings} (${t.target} ${budgetRule.savings}%)`} current={savePct} target={budgetRule.savings} color="emerald" isMinimum lang={lang} />
        </div>
      </div>
    );
  };

  const renderBlockingModalContent = () => {
      if (!blockingError) return null;

      let title = "";
      let message = "";

      if (blockingError.type === 'total') {
          title = lang === 'ar' ? 'تجاوز الراتب' : 'Salary Exceeded';
          message = lang === 'ar' 
            ? `إجمالي المصروفات (${blockingError.current.toLocaleString()}) يتجاوز صافي الراتب (${blockingError.limit.toLocaleString()}). لا يمكن عرض النتائج في حالة العجز.`
            : `Total expenses (${blockingError.current.toLocaleString()}) exceed net salary (${blockingError.limit.toLocaleString()}). Cannot proceed with a deficit.`;
      } else {
          const catName = blockingError.type === 'needs' ? t.needs 
                         : blockingError.type === 'wants' ? t.wants 
                         : t.savings;

          title = lang === 'ar' ? `تجاوز حد ${catName}` : `${catName} Limit Exceeded`;
          message = lang === 'ar'
            ? `مجموع مصاريف "${catName}" هو (${blockingError.current.toLocaleString()})، وهو يتجاوز الحد المسموح به في القاعدة (${blockingError.rulePct}%) والذي يعادل (${Math.round(blockingError.limit).toLocaleString()}).`
            : `Total "${catName}" expenses are (${blockingError.current.toLocaleString()}), which exceeds the allowed limit in the rule (${blockingError.rulePct}%) of (${Math.round(blockingError.limit).toLocaleString()}).`;
      }

      return (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in" dir={isRtl ? 'rtl' : 'ltr'}>
             <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl text-center transform scale-100 transition-all border-t-4 border-red-500">
                <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600">
                   <Ban size={32} />
                </div>
                <h3 className="text-xl font-bold text-gray-800 mb-2">
                   {title}
                </h3>
                <p className="text-gray-600 mb-6 leading-relaxed text-sm">
                   {message}
                </p>
                <p className="text-xs text-red-500 font-bold mb-4 bg-red-50 p-2 rounded">
                    {lang === 'ar' ? 'يجب تقليل المصروفات للمتابعة.' : 'You must reduce expenses to proceed.'}
                </p>
                <button
                    onClick={() => setBlockingError(null)}
                    className="w-full py-3 bg-gray-800 text-white rounded-xl font-bold hover:bg-gray-900 transition-colors shadow-lg"
                >
                    {lang === 'ar' ? 'مراجعة المصروفات' : 'Review Expenses'}
                </button>
             </div>
          </div>
      );
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-28 relative flex flex-col selection:bg-blue-100 selection:text-blue-800" dir={isRtl ? 'rtl' : 'ltr'}>
      <StickyHeader 
        salary={salary} 
        metrics={metrics} 
        onReset={handleReset} 
        currentStep={step} 
        visitorCount={visitorCount}
        lang={lang}
        setLang={setLang}
      />

      {/* Hidden Report for PDF */}
      <div style={{ position: 'fixed', left: '-10000px', top: 0, zIndex: -5, overflow: 'hidden' }}>
        <PrintableReport 
            salary={salary} 
            metrics={metrics} 
            expenses={expenses} 
            lang={lang} 
            budgetRule={budgetRule}
        />
      </div>

      <main className="max-w-4xl mx-auto px-4 flex-grow w-full">

        {/* --- STEP 1: SALARY --- */}
        {step === AppStep.SALARY && (
            <div className="animate-fade-in flex flex-col items-center justify-center min-h-[50vh]">
                 <div className="bg-white rounded-3xl shadow-[0_10px_30px_rgba(0,0,0,0.05)] border border-white/50 p-8 w-full max-w-lg text-center relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-blue-500 via-emerald-500 to-blue-500"></div>

                    <h2 className="text-2xl font-black text-gray-800 mb-6">{t.salaryLabel}</h2>

                    <div className="relative mb-6 group">
                        <input
                        type="number"
                        value={salary || ''}
                        onChange={(e) => setSalary(parseFloat(e.target.value))}
                        placeholder="0"
                        autoFocus
                        className="w-full font-black text-gray-800 border-b-2 border-gray-100 focus:border-blue-600 outline-none bg-transparent transition-all placeholder-gray-200 text-6xl text-center py-6 group-hover:border-blue-200"
                        />
                        <span className={`absolute text-gray-400 font-bold bottom-8 text-xl pointer-events-none transition-all ${isRtl ? 'left-4' : 'right-4'}`}>{t.currency}</span>
                    </div>

                    <div className="flex items-center gap-2 bg-blue-50 p-4 rounded-xl text-xs text-blue-800 mb-8 justify-center border border-blue-100">
                        <Info size={16} className="shrink-0" />
                        <p className="font-medium">{t.salaryHint}</p>
                    </div>

                    <button 
                        onClick={handleNextStep}
                        disabled={salary <= 0}
                        className={`w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-2 transition-all duration-300 transform active:scale-95 ${salary > 0 ? 'bg-gradient-to-r from-blue-600 to-blue-700 text-white shadow-xl shadow-blue-200 hover:shadow-2xl hover:-translate-y-1' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
                    >
                        <span>{t.next}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                    </button>
                 </div>
            </div>
        )}

        {/* --- STEP 2: EXPENSE WIZARD (NEW) --- */}
        {step === AppStep.WIZARD && (
            <ExpenseWizard 
               salary={salary}
               lang={lang}
               onComplete={handleWizardComplete}
            />
        )}

        {/* --- STEP 3: AI ADVISOR (ANALYSIS ONLY) --- */}
        {step === AppStep.ADVISOR && (
            <div className="animate-fade-in w-full max-w-2xl mx-auto">
                <FinancialAdvisor 
                    salary={salary}
                    expenses={expenses}
                    onUpdateRule={setBudgetRule}
                    onFinish={() => setStep(AppStep.EXPENSES)}
                    lang={lang}
                />
            </div>
        )}

        {/* --- STEP 4: EXPENSES LIST --- */}
        {step === AppStep.EXPENSES && (
            <div className="animate-fade-in space-y-6">

                {/* Header Action */}
                <div className="flex flex-col md:flex-row justify-between items-center bg-white p-5 rounded-2xl shadow-sm border border-gray-100 gap-4">
                    <div className="text-center md:text-start flex flex-col gap-1">
                        <h2 className="text-xl font-bold text-gray-800">{t.step2}</h2>
                        <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 mt-1 text-sm text-gray-500">
                           <span>{t.expensesTitle} <span className="bg-gray-100 px-2 py-0.5 rounded-full text-xs font-bold text-gray-600 ml-1">{expenses.length}</span></span>
                           <span className="text-gray-300 hidden sm:inline">|</span>
                           <div className="flex items-center gap-1 bg-blue-50 px-2 py-1 rounded-lg border border-blue-100">
                              <span className="text-blue-800 font-medium text-xs">{t.salaryLabel}:</span>
                              <span className="font-bold text-blue-900">{salary.toLocaleString()}</span>
                              <button 
                                onClick={() => setStep(AppStep.SALARY)} 
                                className="ml-1 text-blue-400 hover:text-blue-600 transition-colors p-1 rounded-full hover:bg-blue-100"
                                title={t.edit}
                              >
                                <Pencil size={12} />
                              </button>
                           </div>
                        </div>
                    </div>
                    <button 
                        onClick={handleOpenAddModal}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl shadow-lg shadow-blue-200 flex items-center gap-2 font-bold transition-all hover:-translate-y-0.5 active:scale-95 w-full md:w-auto justify-center"
                    >
                        <Plus size={20} />
                        {t.addExpense}
                    </button>
                </div>

                {/* The List */}
                <div className="bg-white rounded-2xl shadow-sm border border-gray-100 min-h-[300px] overflow-hidden">
                     <ExpenseTable 
                        expenses={expenses} 
                        salary={salary} 
                        onDelete={handleDeleteExpense} 
                        onEdit={handleOpenEditModal}
                        lang={lang}
                     />
                </div>

                {/* Nav Buttons */}
                <div className="flex justify-between mt-8 gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="px-6 py-3 rounded-xl text-gray-500 hover:bg-gray-100 font-bold flex items-center gap-2 transition-colors"
                     >
                        {isRtl ? <ArrowRight size={20} /> : <ArrowLeft size={20} />}
                        {t.back}
                     </button>

                     <button 
                        onClick={handleNextStep}
                        className="px-8 py-3 rounded-xl bg-emerald-600 hover:bg-emerald-700 text-white font-bold flex items-center gap-2 shadow-lg shadow-emerald-200 transition-all hover:-translate-y-0.5 active:scale-95"
                     >
                        <span>{t.finish}</span>
                        {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
                     </button>
                </div>
            </div>
        )}

        {/* --- STEP 5: DASHBOARD --- */}
        {step === AppStep.DASHBOARD && (
          <div className="animate-fade-in space-y-6">

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Charts Column */}
              <div className="lg:col-span-1 flex flex-col gap-4">
                 <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.expensesTitle}</h3>
                    <FinancialChart metrics={metrics} lang={lang} />
                 </div>

                 <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
                    <h3 className="font-bold text-gray-700 mb-2 text-center text-sm">{t.target} vs {t.actual}</h3>
                    <TargetVsActualChart 
                        salary={salary} 
                        metrics={metrics} 
                        lang={lang} 
                        budgetRule={budgetRule}
                    />
                 </div>
              </div>

              {/* Stats Column */}
              <div className="lg:col-span-2 flex flex-col gap-6">
                 {getAnalysis()}

                 <div className="bg-gradient-to-br from-indigo-900 to-indigo-800 text-white rounded-2xl p-8 shadow-xl shadow-indigo-100 flex flex-col justify-center h-full min-h-[160px] relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 transition-transform group-hover:scale-110"></div>
                    <div className="relative z-10">
                        <h4 className="text-indigo-200 text-sm font-medium mb-2 uppercase tracking-wider">{t.savings}</h4>
                        <div className="text-5xl font-black mb-3 flex items-baseline gap-2 tracking-tight">
                            {metrics.totalSavingsCalculated.toLocaleString()} 
                            <span className="text-xl font-normal text-indigo-300">{t.currency}</span>
                        </div>

                        {metrics.remainingSalary > 0 && (
                        <div className="bg-indigo-950/30 backdrop-blur-sm rounded-lg px-4 py-2 text-sm flex items-center gap-2 w-fit mt-2 border border-white/10">
                            <span className="w-2 h-2 rounded-full bg-green-400 animate-pulse shadow-[0_0_8px_rgba(74,222,128,0.5)]"></span>
                            {t.remaining}: <span className="font-mono font-bold">{metrics.remainingSalary.toLocaleString()}</span>
                        </div>
                        )}
                    </div>
                 </div>

                 <div className="flex flex-col sm:flex-row gap-4">
                     <button 
                        onClick={handlePrevStep}
                        className="flex-1 bg-white border-2 border-gray-100 text-gray-600 py-3 rounded-xl font-bold hover:bg-gray-50 flex justify-center items-center gap-2 transition-all hover:border-gray-200 shadow-sm"
                     >
                        <Edit2 size={16} />
                        {t.edit} {t.step2}
                     </button>

                     <button 
                        onClick={exportPDF}
                        disabled={isExporting}
                        className={`flex-1 bg-slate-800 text-white py-3 rounded-xl font-bold hover:bg-slate-900 flex justify-center items-center gap-2 transition-all shadow-lg hover:shadow-xl hover:-translate-y-0.5 active:scale-95 ${isExporting ? 'opacity-70 cursor-wait' : ''}`}
                     >
                        {isExporting ? <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div> : <Download size={16} />}
                        <span>{t.exportPDF}</span>
                     </button>
                 </div>
              </div>
            </div>

            {/* Expenses Table (Read Only view or quick edit) */}
            {expenses.length > 0 && (
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 animate-fade-in mt-6 overflow-hidden">
                 <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                   <h3 className="font-bold text-gray-800 text-sm">{t.expensesTitle}</h3>
                   <button onClick={() => setStep(AppStep.EXPENSES)} className="text-blue-600 text-xs font-bold hover:underline">
                      {t.edit}
                   </button>
                </div>
                <ExpenseTable 
                  expenses={expenses} 
                  salary={salary} 
                  onDelete={handleDeleteExpense} 
                  onEdit={handleOpenEditModal}
                  lang={lang}
                />
              </div>
            )}
          </div>
        )}

      </main>

      {/* Add Expense Modal */}
      {isModalOpen && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-fade-in"
          onClick={(e) => {
             if (e.target === e.currentTarget) handleCloseModal();
          }}
        >
          <div className="w-full max-w-2xl animate-[fadeIn_0.3s_ease-out]">
            <AddExpenseForm 
              salary={salary} 
              currentTotal={metrics.totalExpenses}
              expenses={expenses}
              onAdd={handleAddExpense}
              editingExpense={editingExpense}
              onUpdate={handleUpdateExpense}
              onCancelEdit={handleCloseModal}
              lang={lang}
            />
          </div>
        </div>
      )}

      {/* Blocking Error Modal */}
      {renderBlockingModalContent()}

      {/* Persistent Footer - Centered always */}
      <footer className="fixed bottom-0 w-full bg-white/95 backdrop-blur-xl border-t border-gray-200 py-3 px-4 shadow-[0_-5px_25px_rgba(0,0,0,0.03)] z-40 flex justify-center items-center transition-all">
        <div className="flex items-center gap-2 text-xs text-slate-500 font-medium bg-slate-50/50 px-4 py-1.5 rounded-full border border-slate-100/50">
           <span>{t.developedBy}</span>
           <a href="https://www.linkedin.com/in/ahmed-alshareef-innovation" target="_blank" rel="noopener noreferrer" className="opacity-80 hover:opacity-100 transition-opacity">
             <img src="./ashareef_logo.png" alt="Logo" className="h-5 object-contain" />
           </a>
        </div>
      </footer>

    </div>
  );
}

const Edit2 = ({size}:{size:number}) => <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;

export default App;

import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Bot, ArrowRight, ArrowLeft, PieChart, Sparkles } from 'lucide-react';
import { Expense, Language, BudgetRule, ExpenseType } from '../types';
import { TRANSLATIONS } from '../constants';

interface FinancialAdvisorProps {
  salary: number;
  expenses: Expense[];
  onUpdateRule: (rule: BudgetRule) => void;
  onFinish: () => void;
  lang: Language;
}

export const FinancialAdvisor: React.FC<FinancialAdvisorProps> = ({ 
  salary, 
  expenses,
  onUpdateRule, 
  onFinish, 
  lang 
}) => {
  const t = TRANSLATIONS[lang];
  const isRtl = lang === 'ar';

  const [isLoading, setIsLoading] = useState(true);
  const [analysisResult, setAnalysisResult] = useState<{ message: string, rule: BudgetRule | null }>({ message: '', rule: null });

  // Function to calculate rule locally if AI fails (Fallback)
  const performLocalAnalysis = () => {
      const totalNeeds = expenses
        .filter(e => e.type === ExpenseType.NEED)
        .reduce((sum, e) => sum + e.amount, 0);

      const needsPct = salary > 0 ? (totalNeeds / salary) * 100 : 0;
      let rule = { needs: 50, wants: 30, savings: 20 };
      let message = "";

      if (needsPct > 65) {
          rule = { needs: 70, wants: 20, savings: 10 };
          message = lang === 'ar'
            ? "نظراً لأن التزاماتك الأساسية مرتفعة (أكثر من 65% من الراتب)، نقترح قاعدة 70/20/10 لتكون الخطة واقعية وقابلة للتطبيق."
            : "Since your essential obligations are high (over 65% of salary), we suggest the 70/20/10 rule to make the plan realistic and achievable.";
      } else if (needsPct > 55) {
          rule = { needs: 60, wants: 20, savings: 20 };
           message = lang === 'ar'
            ? "تشكل الاحتياجات جزءاً كبيراً من دخلك، لذا قمنا بتعديل القاعدة إلى 60/20/20. هذا سيمنحك مرونة أكبر في إدارة المصاريف الضرورية دون الضغط على ميزانيتك."
            : "Needs make up a large part of your income, so we adjusted the rule to 60/20/20. This gives you more flexibility in managing essentials without straining your budget.";
      } else {
           message = lang === 'ar' 
            ? "بناءً على مصاريفك الحالية، وضعك المالي يسمح بتطبيق القاعدة الذهبية 50/30/20. هذا التوزيع يضمن توازناً مثالياً بين الالتزامات، الرفاهية، والادخار للمستقبل." 
            : "Based on your current expenses, your financial situation allows for the golden 50/30/20 rule. This distribution ensures a perfect balance between obligations, lifestyle, and savings.";
      }

      setAnalysisResult({
          message,
          rule
      });
      onUpdateRule(rule);
  };

  useEffect(() => {
    const runAnalysis = async () => {
      setIsLoading(true);

      // Artificial delay for better UX even if local
      await new Promise(resolve => setTimeout(resolve, 1500));

      if (!process.env.API_KEY) {
         performLocalAnalysis();
         setIsLoading(false);
         return;
      }

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        const expensesJSON = JSON.stringify(expenses.map(e => ({ name: e.name, amount: e.amount, type: e.type })));

        const systemInstruction = `
          Context: User Salary = ${salary} ${t.currency}. Language: ${lang === 'ar' ? 'Arabic' : 'English'}.

          ROLE:
          You are "Qawam's Financial Analyzer".

          TASK:
          1. Analyze the provided list of expenses.
          2. Calculate the actual Needs ratio.
          3. Recommend the BEST budget rule based on their actual situation:
             - If Needs are around 50%, recommend 50/30/20.
             - If Needs are high (e.g. > 55%), recommend 60/20/20 or 70/20/10 to be realistic.
             - Explain clearly why this rule fits them.
          4. Return a JSON response.

          OUTPUT FORMAT (JSON ONLY):
          {
            "analysis_message": "A concise explanation (max 3 sentences) of why this rule is chosen based on their high/low needs.",
            "recommended_rule": { "needs": 60, "wants": 20, "savings": 20 }
          }
        `;

        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `User Data: ${expensesJSON}. Analyze and recommend rule in JSON.`,
          config: {
            systemInstruction: systemInstruction,
            temperature: 0.1, 
            responseMimeType: 'application/json'
          },
        });

        const rawText = response.text || "";
        const data = JSON.parse(rawText);

        if (data.recommended_rule && data.analysis_message) {
            setAnalysisResult({
                message: data.analysis_message,
                rule: data.recommended_rule
            });
            onUpdateRule(data.recommended_rule);
        } else {
            throw new Error("Invalid format");
        }

      } catch (err: any) {
        console.warn("AI Analysis Failed (Quota or Error), switching to local fallback.", err);
        // Fallback to local analysis on ANY error (including 429)
        performLocalAnalysis();
      } finally {
        setIsLoading(false);
      }
    };

    runAnalysis();
  }, [salary, expenses, lang, t.currency]);

  return (
    <div className="flex flex-col items-center justify-center min-h-[400px] w-full bg-white rounded-3xl shadow-xl border border-gray-100 p-8 animate-fade-in relative overflow-hidden">

      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-500 via-indigo-500 to-blue-500"></div>

      {isLoading ? (
        <div className="text-center flex flex-col items-center">
            <div className="relative w-20 h-20 mb-6">
                 <div className="absolute inset-0 border-4 border-gray-100 rounded-full"></div>
                 <div className="absolute inset-0 border-4 border-indigo-600 rounded-full border-t-transparent animate-spin"></div>
                 <div className="absolute inset-0 flex items-center justify-center text-indigo-600">
                    <Sparkles size={24} className="animate-pulse" />
                 </div>
            </div>
            <h3 className="text-xl font-bold text-gray-800 mb-2">
                {lang === 'ar' ? 'جاري تحليل مصروفاتك...' : 'Analyzing your expenses...'}
            </h3>
            <p className="text-gray-500 text-sm">
                {lang === 'ar' ? 'يقوم المستشار الذكي باختيار أفضل تقسيم لميزانيتك' : 'The AI advisor is selecting the best budget split'}
            </p>
        </div>
      ) : (
        <div className="w-full max-w-lg animate-fade-in">
            <div className="text-center mb-8">
                <div className="inline-flex items-center justify-center p-3 bg-indigo-50 text-indigo-600 rounded-full mb-4">
                    <Bot size={32} />
                </div>
                <h3 className="text-2xl font-bold text-gray-800 mb-2">
                    {lang === 'ar' ? 'اكتمل التحليل!' : 'Analysis Complete!'}
                </h3>
                <p className="text-gray-600 leading-relaxed">
                    {analysisResult.message}
                </p>
            </div>

            {analysisResult.rule && (
                <div className="bg-gradient-to-br from-gray-50 to-white border border-gray-200 rounded-2xl p-6 mb-8 shadow-sm relative overflow-hidden">
                     <div className="absolute top-0 right-0 p-4 opacity-10">
                        <PieChart size={100} />
                     </div>
                     <h4 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-4 relative z-10">
                         {lang === 'ar' ? 'القاعدة المالية المقترحة' : 'Recommended Budget Rule'}
                     </h4>
                     <div className="flex justify-between items-end relative z-10">
                         <div className="text-center">
                             <div className="text-2xl font-black text-red-500">{analysisResult.rule.needs}%</div>
                             <div className="text-xs font-bold text-gray-400 mt-1">{lang === 'ar' ? 'احتياجات' : 'Needs'}</div>
                         </div>
                         <div className="text-gray-300 font-light text-2xl pb-4">/</div>
                         <div className="text-center">
                             <div className="text-2xl font-black text-amber-500">{analysisResult.rule.wants}%</div>
                             <div className="text-xs font-bold text-gray-400 mt-1">{lang === 'ar' ? 'رغبات' : 'Wants'}</div>
                         </div>
                         <div className="text-gray-300 font-light text-2xl pb-4">/</div>
                         <div className="text-center">
                             <div className="text-2xl font-black text-emerald-500">{analysisResult.rule.savings}%</div>
                             <div className="text-xs font-bold text-gray-400 mt-1">{lang === 'ar' ? 'ادخار' : 'Savings'}</div>
                         </div>
                     </div>
                </div>
            )}

            <button 
                onClick={onFinish}
                className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg shadow-indigo-200 transition-all hover:-translate-y-1 flex items-center justify-center gap-2"
            >
                {lang === 'ar' ? 'عرض النتائج التفصيلية' : 'View Detailed Results'}
                {isRtl ? <ArrowLeft size={20} /> : <ArrowRight size={20} />}
            </button>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { DashboardMetrics, AppStep, Language } from '../types';
import { RotateCcw, Users, Globe } from 'lucide-react';
import { TRANSLATIONS } from '../constants';

interface StickyHeaderProps {
